export default Header;

import React, { useState, useMemo } from 'react';
import { Search, Calculator, AlertCircle, Package, ArrowLeftRight } from 'lucide-react';
import { SalesItem, Material, Recipe } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
}

const QuickQueryPage: React.FC<Props> = ({ items, materials, recipes }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [queryQuantity, setQueryQuantity] = useState<number>(1);

  const selectedItem = useMemo(() => items.find(i => i.id === selectedItemId), [items, selectedItemId]);
  const itemRecipe = useMemo(() => recipes.find(r => r.itemId === selectedItemId), [recipes, selectedItemId]);

  const calculationResults = useMemo(() => {
    if (!itemRecipe) return [];

    return itemRecipe.ingredients.map(ing => {
      const mat = materials.find(m => m.id === ing.materialId);
      return {
        materialName: mat?.name || 'غير معروف',
        unit: mat?.unit || '',
        perUnit: ing.quantity,
        totalRequired: ing.quantity * queryQuantity
      };
    });
  }, [itemRecipe, materials, queryQuantity]);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Query Input Section */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="bg-blue-500 p-2 rounded-lg">
            <Calculator className="w-6 h-6 text-white" />
          </div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-white">حاسبة الاستهلاك التقديري</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">احسب كمية الخامات المطلوبة لعدد معين من الوجبات</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الصنف</label>
            <select
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-medium transition-colors"
              value={selectedItemId}
              onChange={(e) => setSelectedItemId(e.target.value)}
            >
              <option value="">-- اختر صنفاً للاستعلام --</option>
              {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الكمية التقديرية</label>
            <input
              type="number"
              min="1"
              step="any"
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-mono font-bold transition-colors"
              value={queryQuantity || ''}
              onChange={(e) => setQueryQuantity(parseFloat(e.target.value) || 0)}
              placeholder="مثال: 50"
            />
          </div>
        </div>
      </div>

      {/* Results Section */}
      {selectedItemId ? (
        itemRecipe ? (
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300">
            <div className="p-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 flex justify-between items-center">
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white">نتائج الحساب لـ {queryQuantity} وحدة</h4>
                <p className="text-xs text-slate-500 dark:text-slate-400">بناءً على الوصفة المعتمدة لـ {selectedItem?.name}</p>
              </div>
              <div className="bg-white dark:bg-slate-800 px-3 py-1.5 rounded-lg border border-slate-200 dark:border-slate-700 text-sm font-bold text-blue-600 dark:text-blue-400">
                {calculationResults.length} خامة مطلوبة
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-slate-50/50 dark:bg-slate-800/20 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">
                  <tr>
                    <th className="px-6 py-4">الخامة</th>
                    <th className="px-6 py-4 text-center">لكل وحدة</th>
                    <th className="px-6 py-4 text-left">الإجمالي المطلوب</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {calculationResults.map((res, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <Package className="w-4 h-4 text-slate-300 group-hover:text-blue-500 transition-colors" />
                          <span className="font-bold text-slate-700 dark:text-slate-200">{res.materialName}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <span className="text-xs text-slate-400 dark:text-slate-500 font-mono">{res.perUnit.toFixed(3)} {res.unit}</span>
                      </td>
                      <td className="px-6 py-4 text-left">
                        <span className="font-mono font-bold text-blue-600 dark:text-blue-400 text-lg">
                          {res.totalRequired.toLocaleString(undefined, { minimumFractionDigits: 3 })}
                        </span>
                        <span className="mr-1.5 text-xs text-slate-400 font-bold">{res.unit}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="p-4 bg-blue-50/30 dark:bg-blue-900/10 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2 text-xs text-blue-600 dark:text-blue-400 font-medium">
              <ArrowLeftRight className="w-3.5 h-3.5" />
              <span>هذه البيانات استرشادية فقط ولا يتم تسجيلها في سجلات الاستهلاك الفعلي.</span>
            </div>
          </div>
        ) : (
          <div className="bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/30 p-8 rounded-2xl flex flex-col items-center gap-4 animate-in shake duration-500">
            <AlertCircle className="w-12 h-12 text-rose-500" />
            <div className="text-center">
              <h4 className="font-bold text-rose-800 dark:text-rose-400">وصفة غير موجودة</h4>
              <p className="text-sm text-rose-600 dark:text-rose-500 mt-1">يجب عليك إعداد وصفة للصنف "{selectedItem?.name}" أولاً من صفحة "إدارة الوصفات".</p>
            </div>
          </div>
        )
      ) : (
        <div className="bg-slate-100/50 dark:bg-slate-800/30 border-2 border-dashed border-slate-200 dark:border-slate-800 p-20 rounded-2xl flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4">
          <Search className="w-16 h-16 opacity-10" />
          <p className="font-medium">اختر صنفاً من القائمة لبدء الحساب التقديري</p>
        </div>
      )}
    </div>
  );
};

export default QuickQueryPage;

import React, { useState, useMemo } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw, Search, Package, Utensils } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, AggregatedReportItem, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  // Date filter states
  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  // New Filter States
  const [selectedMaterialId, setSelectedMaterialId] = useState<string>('');
  const [selectedItemId, setSelectedItemId] = useState<string>('');

  // Filtered sales based on selected date range and selected item
  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const saleDate = sale.date;
      const dateMatch = saleDate >= startDate && saleDate <= endDate;
      const itemMatch = selectedItemId ? sale.itemId === selectedItemId : true;
      return dateMatch && itemMatch;
    });
  }, [sales, startDate, endDate, selectedItemId]);

  const aggregatedData = useMemo(() => {
    const reportMap: Record<string, { name: string; unit: string; total: number }> = {};

    // Initialize or filter materials
    materials.forEach(m => {
      if (!selectedMaterialId || m.id === selectedMaterialId) {
        reportMap[m.id] = { name: m.name, unit: m.unit, total: 0 };
      }
    });

    filteredSales.forEach(sale => {
      const recipe = recipes.find(r => r.itemId === sale.itemId);
      if (recipe) {
        recipe.ingredients.forEach(ing => {
          if (reportMap[ing.materialId]) {
            reportMap[ing.materialId].total += ing.quantity * sale.quantitySold;
          }
        });
      }
    });

    // If a material filter is active but no sales exist for it, we might still want to see 0 or just filter it out.
    // Here we filter out items with 0 total unless a specific material is selected.
    return Object.values(reportMap).filter(item => selectedMaterialId ? true : item.total > 0);
  }, [materials, recipes, filteredSales, selectedMaterialId]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);
      const recipe = recipes.find(r => r.itemId === itemId);

      if (item && recipe) {
        // Filter ingredients based on selected material
        const filteredIngredients = recipe.ingredients
          .filter(ing => !selectedMaterialId || ing.materialId === selectedMaterialId)
          .map(ing => {
            const mat = materials.find(m => m.id === ing.materialId);
            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              consumedQuantity: ing.quantity * qtySold
            };
          });

        if (filteredIngredients.length > 0) {
          results.push({
            itemName: item.name,
            quantitySold: qtySold,
            ingredients: filteredIngredients
          });
        }
      }
    });
    return results;
