    await client.execute("CREATE INDEX IF NOT EXISTS idx_recipes_item ON recipes(item_id, restaurant_id)");
  } catch (error) {
    console.error("Database Init Error:", error);
  }
};

export const db = {
  // Restaurants
  getRestaurants: async (): Promise<Restaurant[]> => {
    const rs = await client.execute("SELECT * FROM restaurants ORDER BY name");
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string }));
  },
  saveRestaurant: async (r: Restaurant) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO restaurants (id, name) VALUES (?, ?)",
      args: [r.id, r.name]
    });
  },
  deleteRestaurant: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_items WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM materials WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM restaurants WHERE id = ?", args: [id] }
    ], "write");
  },

  // Material Groups
  getMaterialGroups: async (restaurantId: string): Promise<MaterialGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM material_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveMaterialGroup: async (g: MaterialGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteMaterialGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE materials SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Sales Item Groups
  getSalesItemGroups: async (restaurantId: string): Promise<SalesItemGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveSalesItemGroup: async (g: SalesItemGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteSalesItemGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE sales_items SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Materials
  getMaterials: async (restaurantId: string): Promise<Material[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM materials WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string, 
      unit: row.unit as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [m.id, m.name, m.unit, m.groupId || null, m.restaurantId]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (restaurantId: string): Promise<SalesItem[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_items WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name, group_id, restaurant_id) VALUES (?, ?, ?, ?)",
      args: [i.id, i.name, i.groupId || null, i.restaurantId]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (restaurantId: string): Promise<Recipe[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM recipes WHERE restaurant_id = ?",
      args: [restaurantId]
    });
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [], restaurantId: row.restaurant_id as string };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string || undefined,
        subItemId: row.sub_item_id as string || undefined,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ? AND restaurant_id = ?", args: [recipe.itemId, recipe.restaurantId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [
          recipe.itemId, 
          ing.materialId || null, 
          ing.subItemId || null, 
          ing.quantity, 
          recipe.restaurantId
        ]
      }))
    ];
    await client.batch(queries, "write");
  },

  // Sales
  getSales: async (restaurantId: string): Promise<SaleEntry[]> => {
    const rs = await client.execute({
      sql: "SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date, restaurant_id as restaurantId FROM sales WHERE restaurant_id = ? ORDER BY sale_date DESC",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({
      id: row.id as string,
      itemId: row.itemId as string,
      quantitySold: row.quantitySold as number,
      date: row.date as string,
      restaurantId: row.restaurantId as string
    }));
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date, s.restaurantId]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Calculator, Save, Package, UtensilsCrossed, ArrowRightLeft } from 'lucide-react';
import { SalesItem, Material, Recipe, RecipeIngredient } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
  onSave: (recipe: Omit<Recipe, 'restaurantId'>) => Promise<void>;
}

const RecipeBuilderPage: React.FC<Props> = ({ items, materials, recipes, onSave }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [localIngredients, setLocalIngredients] = useState<RecipeIngredient[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const existing = recipes.find(r => r.itemId === selectedItemId);
    setLocalIngredients(existing ? [...existing.ingredients] : []);
  }, [selectedItemId, recipes]);

  const addIngredient = (type: 'material' | 'item') => {
    if (!selectedItemId) return;

    if (type === 'material') {
      if (materials.length === 0) return;
      setLocalIngredients([...localIngredients, { materialId: materials[0].id, quantity: 0 }]);
    } else {
      if (items.length === 0) return;
      // Filter out the selected item itself to prevent circular reference
      const otherItems = items.filter(i => i.id !== selectedItemId);
      if (otherItems.length === 0) return;
      setLocalIngredients([...localIngredients, { subItemId: otherItems[0].id, quantity: 0 }]);
    }
  };

  const updateIngredient = (idx: number, field: keyof RecipeIngredient, value: any) => {
    const next = [...localIngredients];
    next[idx] = { ...next[idx], [field]: value };

    // Ensure if we update materialId, subItemId is cleared and vice versa
    if (field === 'materialId') delete next[idx].subItemId;
    if (field === 'subItemId') delete next[idx].materialId;

    setLocalIngredients(next);
  };

  const toggleType = (idx: number) => {
    const current = localIngredients[idx];
    const next = [...localIngredients];
    if (current.materialId) {
      const otherItems = items.filter(i => i.id !== selectedItemId);
      next[idx] = { subItemId: otherItems[0]?.id || '', quantity: current.quantity };
    } else {
      next[idx] = { materialId: materials[0]?.id || '', quantity: current.quantity };
    }
    setLocalIngredients(next);
  };

  const removeIngredient = (idx: number) => {
    setLocalIngredients(localIngredients.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!selectedItemId) return;
    setIsSaving(true);
    await onSave({ itemId: selectedItemId, ingredients: localIngredients });
    setIsSaving(false);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">اختر الصنف الرئيسي لتعديل وصفته:</label>
        <select
          className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium transition-colors"
          value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}
        >
          <option value="">-- اختر صنفاً --</option>
          {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
        </select>
      </div>

      {selectedItemId && (
        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-2 transition-colors">
          <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row justify-between items-center bg-slate-50/50 dark:bg-slate-800/50 gap-4">
            <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
              وصفة: <span className="text-emerald-600 dark:text-emerald-400">{items.find(i => i.id === selectedItemId)?.name}</span>
            </h3>
            <div className="flex flex-wrap gap-2">
               <button onClick={() => addIngredient('material')} className="flex items-center gap-2 text-xs bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-colors"><Package className="w-3.5 h-3.5" /> إضافة خامة</button>
               <button onClick={() => addIngredient('item')} className="flex items-center gap-2 text-xs bg-blue-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-blue-700 transition-colors"><UtensilsCrossed className="w-3.5 h-3.5" /> إضافة صنف مجهز</button>
               <button onClick={handleSave} disabled={isSaving} className="flex items-center gap-2 text-sm bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 transition-all hover:scale-105 active:scale-95"><Save className="w-4 h-4" /> {isSaving ? 'جاري الحفظ...' : 'حفظ الوصفة'}</button>
            </div>
          </div>
          <div className="p-6 space-y-4">
            {localIngredients.length === 0 ? (
              <div className="text-center py-12 text-slate-400 dark:text-slate-600"><Calculator className="w-12 h-12 mx-auto mb-3 opacity-20" /><p>لا توجد مكونات في هذه الوصفة. ابدأ بإضافة خامات أو أصناف مجهزة.</p></div>
            ) : (
              localIngredients.map((ing, idx) => {
                const isSubItem = !!ing.subItemId;
                return (
                  <div key={idx} className={`flex flex-col md:flex-row gap-4 items-start p-4 rounded-xl border transition-colors ${
                    isSubItem 
                      ? 'bg-blue-50/30 border-blue-100 dark:bg-blue-900/10 dark:border-blue-800/30' 
                      : 'bg-slate-50/50 border-slate-100 dark:bg-slate-800/30 dark:border-slate-800/50'
                  }`}>
                    <div className="flex-1 w-full">
                      <div className="flex items-center justify-between mb-1 mr-1">
                        <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1">
                          {isSubItem ? <><UtensilsCrossed className="w-3 h-3 text-blue-500" /> صنف مجهز</> : <><Package className="w-3 h-3 text-slate-500" /> خامة أساسية</>}
                        </label>
                        <button onClick={() => toggleType(idx)} className="text-[10px] text-emerald-500 hover:underline flex items-center gap-1 font-bold">
                          <ArrowRightLeft className="w-3 h-3" /> تبديل النوع
                        </button>
                      </div>
                      <select 
                        className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 transition-colors" 
                        value={isSubItem ? ing.subItemId : ing.materialId} 
                        onChange={(e) => updateIngredient(idx, isSubItem ? 'subItemId' : 'materialId', e.target.value)}
                      >
                        {isSubItem ? (
                          items.filter(i => i.id !== selectedItemId).map(i => <option key={i.id} value={i.id}>{i.name}</option>)
                        ) : (
                          materials.map(m => <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>)
                        )}
                      </select>
                    </div>
                    <div className="w-full md:w-48">
                      <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الكمية لكل وحدة</label>
                      <input 
                        type="number" step="0.001" 
                        className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white font-mono font-bold transition-colors" 
                        value={ing.quantity || ''} 
                        onChange={(e) => updateIngredient(idx, 'quantity', parseFloat(e.target.value) || 0)} 
                      />
                    </div>
                    <button onClick={() => removeIngredient(idx)} className="p-2.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl md:mt-5 self-end"><Trash2 className="w-5 h-5" /></button>
                  </div>
                );
              })
            )}
          </div>
        </div>
      )}
    </div>
  );
};

export default RecipeBuilderPage;

import React, { useState, useMemo } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw, Search, Package, Utensils } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  const [selectedMaterialId, setSelectedMaterialId] = useState<string>('');
  const [selectedItemId, setSelectedItemId] = useState<string>('');

  // Recursive function to flatten consumption from nested recipes
  const getFlattenedConsumption = useCallback((itemId: string, multiplier: number, memo: Record<string, number> = {}, visited: Set<string> = new Set()): Record<string, number> => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe || visited.has(itemId)) return memo;

    visited.add(itemId);

    recipe.ingredients.forEach(ing => {
      const qty = ing.quantity * multiplier;
      if (ing.materialId) {
        memo[ing.materialId] = (memo[ing.materialId] || 0) + qty;
      } else if (ing.subItemId) {
        getFlattenedConsumption(ing.subItemId, qty, memo, visited);
      }
    });

    visited.delete(itemId);
    return memo;
  }, [recipes]);

  // Filtered sales based on selected date range and selected item
  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const saleDate = sale.date;
      const dateMatch = saleDate >= startDate && saleDate <= endDate;
      const itemMatch = selectedItemId ? sale.itemId === selectedItemId : true;
      return dateMatch && itemMatch;
    });
  }, [sales, startDate, endDate, selectedItemId]);

  const aggregatedData = useMemo(() => {
    const consumptionMap: Record<string, number> = {};

    filteredSales.forEach(sale => {
      getFlattenedConsumption(sale.itemId, sale.quantitySold, consumptionMap);
    });

    const results = materials.map(m => ({
      name: m.name,
      unit: m.unit,
      total: consumptionMap[m.id] || 0,
      id: m.id
    }));

    return results.filter(item => {
      const matchesMaterial = selectedMaterialId ? item.id === selectedMaterialId : true;
      const hasValue = item.total > 0;
      return matchesMaterial && (selectedMaterialId ? true : hasValue);
    });
  }, [materials, filteredSales, getFlattenedConsumption, selectedMaterialId]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);

      if (item) {
        const flatIngs = getFlattenedConsumption(itemId, 1);

        const ingredients = Object.entries(flatIngs)
          .filter(([matId]) => !selectedMaterialId || matId === selectedMaterialId)
          .map(([matId, qtyPerUnit]) => {
            const mat = materials.find(m => m.id === matId);
            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              consumedQuantity: qtyPerUnit * qtySold
            };
          });

        if (ingredients.length > 0) {
          results.push({
            itemName: item.name,
            quantitySold: qtySold,
            ingredients
          });
        }
      }
    });
    return results;
  }, [items, filteredSales, materials, selectedMaterialId, getFlattenedConsumption]);

  const resetFilter = () => {
    setStartDate(firstDayOfMonth);
    setEndDate(today);
    setSelectedMaterialId('');
    setSelectedItemId('');
  };

  const exportCSV = () => {
    const now = new Date().toLocaleString('ar-EG');
    const reportTitle = reportType === 'aggregated' ? "تقرير استهلاك الخامات (تجميعي)" : "تقرير استهلاك الخامات (تفصيلي)";

    let csvContent = `نظام CulinaTrack لإدارة استهلاك المطاعم\n`;
    csvContent += `نوع التقرير,${reportTitle}\n`;
    csvContent += `من تاريخ,${startDate}\n`;
    csvContent += `إلى تاريخ,${endDate}\n`;
    if (selectedItemId) csvContent += `الصنف المفلتر,${items.find(i => i.id === selectedItemId)?.name}\n`;
    if (selectedMaterialId) csvContent += `الخامة المفلترة,${materials.find(m => m.id === selectedMaterialId)?.name}\n`;
    csvContent += `تاريخ الاستخراج,${now}\n`;
    csvContent += `\n`;

    if (reportType === 'aggregated') {
      csvContent += "الخامة,وحدة القياس,إجمالي الاستهلاك الفعلي\n";
      aggregatedData.forEach(row => {
        csvContent += `"${row.name}","${row.unit}",${row.total.toFixed(3)}\n`;
      });
    } else {
      csvContent += "الصنف,الكمية المباعة,الخامة المستهلكة,الكمية المستهلكة,الوحدة\n";
      detailedData.forEach(item => {
        item.ingredients.forEach(ing => {
          csvContent += `"${item.itemName}",${item.quantitySold},"${ing.materialName}",${ing.consumedQuantity.toFixed(3)},"${ing.unit}"\n`;
        });
      });
    }

    const BOM = "\uFEFF";
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    const url = URL.createObjectURL(blob);
    link.setAttribute("href", url);
    link.setAttribute("download", `CulinaTrack_Report_${reportType}.csv`);
    link.click();
  };

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Branding Header for Print */}
      <div className="hidden print:flex items-center justify-between mb-8 border-b-2 border-emerald-500 pb-4">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg"><ChefHat className="w-8 h-8 text-white" /></div>
          <div>
            <h1 className="text-2xl font-bold text-slate-800">CulinaTrack</h1>
            <p className="text-xs text-slate-500">نظام إدارة استهلاك المطاعم</p>
          </div>
        </div>
        <div className="text-left text-right">
          <h2 className="text-xl font-bold text-slate-700">تقرير استهلاك الخامات النهائي</h2>
          <p className="text-sm text-slate-500">الفترة: {startDate} إلى {endDate}</p>
        </div>
      </div>

      {/* Filter Section */}
      <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200 no-print transition-colors">
        <div className="flex items-center gap-2 mb-6 text-slate-700 font-bold border-b border-slate-100 pb-4">
          <Filter className="w-5 h-5 text-emerald-500" />
          <h3>تصفية التقارير الذكية</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 items-end">
          <div className="space-y-1.5">
            <label className="flex items-center gap-1.5 text-xs font-bold text-slate-500 mr-1"><Calendar className="w-3.5 h-3.5" /> من تاريخ</label>
            <input type="date" className="w-full border border-slate-200 rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white text-sm" value={startDate} onChange={(e) => setStartDate(e.target.value)} />
          </div>
          <div className="space-y-1.5">
            <label className="flex items-center gap-1.5 text-xs font-bold text-slate-500 mr-1"><Calendar className="w-3.5 h-3.5" /> إلى تاريخ</label>
            <input type="date" className="w-full border border-slate-200 rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white text-sm" value={endDate} onChange={(e) => setEndDate(e.target.value)} />
          </div>
          <div className="space-y-1.5">
            <label className="flex items-center gap-1.5 text-xs font-bold text-slate-500 mr-1"><Package className="w-3.5 h-3.5" /> تصفية بالخامة</label>
            <select className="w-full border border-slate-200 rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white text-sm" value={selectedMaterialId} onChange={(e) => setSelectedMaterialId(e.target.value)}>
              <option value="">كل الخامات</option>
              {materials.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
          <div className="space-y-1.5">
            <label className="flex items-center gap-1.5 text-xs font-bold text-slate-500 mr-1"><Utensils className="w-3.5 h-3.5" /> تصفية بالصنف</label>
            <select className="w-full border border-slate-200 rounded-xl px-3 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white text-sm" value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}>
              <option value="">كل الأصناف</option>
              {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
        </div>

        <div className="mt-6 flex justify-end">
          <button onClick={resetFilter} className="flex items-center gap-2 px-4 py-2 text-slate-400 hover:text-rose-500 transition-all font-bold text-sm">
            <RotateCcw className="w-4 h-4" /> إعادة تعيين كافة الفلاتر
          </button>
        </div>
      </div>

      <div className="flex flex-col md:flex-row items-center justify-between gap-4 no-print">
        <div className="flex bg-white p-1 rounded-2xl border border-slate-200 shadow-sm w-fit transition-colors">
          <button onClick={() => setReportType('aggregated')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${reportType === 'aggregated' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500'}`}><Layers className="w-4 h-4" /> تقرير تجميعي</button>
          <button onClick={() => setReportType('detailed')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${reportType === 'detailed' ? 'bg-emerald-500 text-white shadow-lg shadow-emerald-500/30' : 'text-slate-500'}`}><List className="w-4 h-4" /> تقرير تفصيلي</button>
        </div>

        <div className="flex gap-3">
          <button onClick={exportCSV} className="flex items-center gap-2 text-sm text-emerald-700 border border-emerald-100 bg-emerald-50 px-4 py-2 rounded-xl hover:bg-emerald-100 transition-colors font-bold"><FileSpreadsheet className="w-4 h-4" /> تصدير CSV</button>
          <button onClick={() => window.print()} className="flex items-center gap-2 text-sm text-slate-700 border border-slate-200 bg-white px-4 py-2 rounded-xl hover:bg-slate-50 transition-colors font-bold"><Printer className="w-4 h-4" /> طباعة PDF</button>
        </div>
      </div>

      {reportType === 'aggregated' ? (
        <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden print:border-none transition-colors">
          <div className="p-6 border-b border-slate-100 bg-slate-50 print:bg-white">
            <h3 className="font-bold text-slate-800">إجمالي استهلاك الخامات (بما في ذلك الوصفات المتداخلة)</h3>
            <p className="text-xs text-slate-500">مجمع وشامل لكافة المكونات المجهزة</p>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-slate-50/50">
                <tr>
                  <th className="px-6 py-4 font-semibold text-slate-600">الخامة النهائية</th>
                  <th className="px-6 py-4 font-semibold text-slate-600">وحدة القياس</th>
                  <th className="px-6 py-4 font-semibold text-slate-600 text-left">إجمالي الاستهلاك</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100">
                {aggregatedData.length > 0 ? aggregatedData.map((data, i) => (
                  <tr key={i} className="hover:bg-slate-50 transition-colors">
                    <td className="px-6 py-4 font-bold text-slate-700">{data.name}</td>
                    <td className="px-6 py-4 text-slate-500">{data.unit}</td>
                    <td className="px-6 py-4 font-mono font-bold text-emerald-600 text-left">{data.total.toLocaleString(undefined, { minimumFractionDigits: 3 })}</td>
                  </tr>
                )) : (
                  <tr><td colSpan={3} className="px-6 py-12 text-center text-slate-400 italic">لا توجد مبيعات تتضمن هذه الخامات في الفترة المحددة</td></tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
          {detailedData.map((item, idx) => (
            <div key={idx} className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden print:break-inside-avoid">
              <div className="p-4 bg-slate-900 text-white flex justify-between items-center print:bg-slate-100 print:text-slate-900 print:border-b">
                <span className="text-lg font-bold">{item.itemName}</span>
                <span className="bg-emerald-500 px-3 py-1 rounded-lg text-sm font-bold">المباع: {item.quantitySold}</span>
              </div>
              <table className="w-full text-right">
                <tbody className="divide-y divide-slate-50">
                  {item.ingredients.map((ing, iIdx) => (
                    <tr key={iIdx}>
                      <td className="px-6 py-3 text-sm text-slate-600">{ing.materialName}</td>
                      <td className="px-6 py-3 text-sm font-mono font-bold text-slate-800 text-left">{ing.consumedQuantity.toLocaleString(undefined, { minimumFractionDigits: 3 })} {ing.unit}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          ))}
          {detailedData.length === 0 && <div className="bg-white p-12 text-center text-slate-400 rounded-2xl border">لا توجد بيانات للعرض بناءً على التصفية</div>}
        </div>
      )}
    </div>
  );
};

export default ReportsPage;

import React, { useState, useMemo, useCallback } from 'react';
import { Calculator, Package, ArrowLeftRight, Search, UtensilsCrossed } from 'lucide-react';
import { SalesItem, Material, Recipe } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
}

const QuickQueryPage: React.FC<Props> = ({ items, materials, recipes }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [queryQuantity, setQueryQuantity] = useState<number>(1);

  // Recursive function to resolve total material consumption
  const resolveFlattenedIngredients = useCallback((itemId: string, multiplier: number, memo: Record<string, number> = {}, visited: Set<string> = new Set()): Record<string, number> => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe || visited.has(itemId)) return memo;

    visited.add(itemId);

    recipe.ingredients.forEach(ing => {
      const totalQty = ing.quantity * multiplier;
      if (ing.materialId) {
        memo[ing.materialId] = (memo[ing.materialId] || 0) + totalQty;
      } else if (ing.subItemId) {
        resolveFlattenedIngredients(ing.subItemId, totalQty, memo, visited);
      }
    });

    visited.delete(itemId);
    return memo;
  }, [recipes]);

  const selectedItem = useMemo(() => items.find(i => i.id === selectedItemId), [items, selectedItemId]);
  const itemRecipe = useMemo(() => recipes.find(r => r.itemId === selectedItemId), [recipes, selectedItemId]);

  const calculationResults = useMemo(() => {
    if (!selectedItemId) return [];

    const flattened = resolveFlattenedIngredients(selectedItemId, queryQuantity);

    return Object.entries(flattened).map(([matId, totalQty]) => {
      const mat = materials.find(m => m.id === matId);
      return {
        materialName: mat?.name || 'خامة غير معروفة',
        unit: mat?.unit || '',
        totalRequired: totalQty
      };
    });
  }, [selectedItemId, queryQuantity, materials, resolveFlattenedIngredients]);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="bg-blue-500 p-2 rounded-lg"><Calculator className="w-6 h-6 text-white" /></div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-white">حاسبة الاستهلاك التقديري (المتداخلة)</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">تحليل تلقائي لكافة مكونات الوصفات المجهزة والخامات</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الصنف الرئيسي</label>
            <select
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-medium transition-colors"
              value={selectedItemId}
              onChange={(e) => setSelectedItemId(e.target.value)}
            >
              <option value="">-- اختر صنفاً للاستعلام --</option>
              {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الكمية المطلوبة</label>
            <input
              type="number" min="0.001" step="any"
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-mono font-bold transition-colors"
              value={queryQuantity || ''}
              onChange={(e) => setQueryQuantity(parseFloat(e.target.value) || 0)}
              placeholder="مثال: 10"
            />
          </div>
        </div>
      </div>

      {selectedItemId ? (
        itemRecipe ? (
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-4 duration-300 transition-colors">
            <div className="p-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 flex justify-between items-center">
              <div>
                <h4 className="font-bold text-slate-800 dark:text-white">الخامات النهائية المطلوبة لـ {queryQuantity} وحدة</h4>
                <p className="text-xs text-slate-500 dark:text-slate-400">شاملة لكافة الوصفات المتداخلة لـ {selectedItem?.name}</p>
              </div>
              <div className="bg-blue-50 dark:bg-blue-900/20 px-3 py-1.5 rounded-lg text-xs font-bold text-blue-600 dark:text-blue-400 border border-blue-100 dark:border-blue-800/50 flex items-center gap-1">
                <UtensilsCrossed className="w-3.5 h-3.5" /> تحليل كامل
              </div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-right">
                <thead className="bg-slate-50/50 dark:bg-slate-800/20 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase">
                  <tr>
                    <th className="px-6 py-4">الخامة الأساسية</th>
                    <th className="px-6 py-4 text-left">إجمالي الكمية الصافية</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                  {calculationResults.map((res, idx) => (
                    <tr key={idx} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                      <td className="px-6 py-4">
                        <div className="flex items-center gap-3">
                          <Package className="w-4 h-4 text-slate-300 group-hover:text-blue-500 transition-colors" />
                          <span className="font-bold text-slate-700 dark:text-slate-200">{res.materialName}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-left">
                        <span className="font-mono font-bold text-blue-600 dark:text-blue-400 text-lg">
                          {res.totalRequired.toLocaleString(undefined, { minimumFractionDigits: 3 })}
                        </span>
                        <span className="mr-1.5 text-xs text-slate-400 font-bold">{res.unit}</span>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            <div className="p-4 bg-blue-50/30 dark:bg-blue-900/10 border-t border-slate-100 dark:border-slate-800 flex items-center gap-2 text-xs text-blue-600 dark:text-blue-400 font-medium">
              <ArrowLeftRight className="w-3.5 h-3.5" />
              <span>تم تحليل الوصفة وتفكيك كافة الأصناف المجهزة إلى خاماتها الأصلية.</span>
            </div>
          </div>
        ) : (
          <div className="bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/30 p-8 rounded-2xl flex flex-col items-center gap-4 animate-in shake duration-500">
            <UtensilsCrossed className="w-12 h-12 text-rose-500" />
            <div className="text-center">
              <h4 className="font-bold text-rose-800 dark:text-rose-400">وصفة غير مكتملة</h4>
              <p className="text-sm text-rose-600 dark:text-rose-500 mt-1">يجب عليك إعداد وصفة للصنف "{selectedItem?.name}" في صفحة إدارة الوصفات.</p>
            </div>
          </div>
        )
      ) : (
        <div className="bg-slate-100/50 dark:bg-slate-800/30 border-2 border-dashed border-slate-200 dark:border-slate-800 p-20 rounded-2xl flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4">
          <Search className="w-16 h-16 opacity-10" />
          <p className="font-medium">اختر صنفاً مجهزاً أو وجبة رئيسية لبدء التحليل</p>
        </div>
      )}
    </div>
  );
};

export default QuickQueryPage;

import React, { useState } from 'react';
import { Save, History, ShoppingCart, Loader2, Trash2, Edit3, X, Check, Plus, AlertCircle } from 'lucide-react';
import { SalesItem, SaleEntry } from '../types';

interface Props {
  items: SalesItem[];
  sales: SaleEntry[];
  // Fix: onSave handler now expects Omit[] to match parent logic
  onSave: (newSales: Omit<SaleEntry, 'restaurantId'>[]) => Promise<void>;
  onDeleteSale: (id: string) => Promise<void>;
  onUpdateSale: (id: string, quantity: number) => Promise<void>;
}

interface NewSaleRow {
  tempId: string;
  itemId: string;
  quantity: number;
}

const SalesEntryPage: React.FC<Props> = ({ items, sales, onSave, onDeleteSale, onUpdateSale }) => {
  const [rows, setRows] = useState<NewSaleRow[]>([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
  const [date, setDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isSaving, setIsSaving] = useState(false);

  const [editingSaleId, setEditingSaleId] = useState<string | null>(null);
  const [editQuantity, setEditQuantity] = useState<number>(0);

  const existingSalesForDate = sales.filter(s => s.date === date);

  const addRow = () => {
    setRows([...rows, { tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
  };

  const removeRow = (tempId: string) => {
    if (rows.length === 1) {
      setRows([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
    } else {
      setRows(rows.filter(r => r.tempId !== tempId));
    }
  };

  const updateRow = (tempId: string, field: keyof NewSaleRow, value: any) => {
    setRows(rows.map(r => r.tempId === tempId ? { ...r, [field]: value } : r));
  };

  const handleSave = async () => {
    const validRows = rows.filter(r => r.itemId && r.quantity > 0);
    if (validRows.length === 0) return alert('يرجى اختيار صنف وإدخال كمية لواحد على الأقل');

    setIsSaving(true);
    try {
      // Fix: Removed explicit : SaleEntry[] type because restaurantId is added by parent
      const newEntries = validRows.map(r => ({
        id: crypto.randomUUID() as `${string}-${string}-${string}-${string}-${string}`,
        itemId: r.itemId,
        quantitySold: r.quantity,
        date
      }));

      await onSave(newEntries);
      setRows([{ tempId: crypto.randomUUID(), itemId: '', quantity: 0 }]);
    } catch (error) {
      console.error(error);
    } finally {
      setIsSaving(false);
    }
  };

  const startEdit = (sale: SaleEntry) => {
    setEditingSaleId(sale.id);
    setEditQuantity(sale.quantitySold);
  };

  return (
    <div className="max-w-4xl mx-auto space-y-8">
      {/* New Sales Form with Dynamic Rows */}
      <section className="space-y-6">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 flex flex-col md:flex-row md:items-center justify-between gap-4 transition-colors">
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-white flex items-center gap-2">
              <ShoppingCart className="w-5 h-5 text-emerald-500" /> تسجيل مبيعات جديدة
            </h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">اختر الأصناف وأدخل الكميات لتاريخ اليوم</p>
          </div>
          <input 
            type="date" 
            className="border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2 outline-none focus:ring-2 focus:ring-emerald-500 font-medium bg-slate-50 dark:bg-slate-800 dark:text-white" 
            value={date} 
            onChange={(e) => setDate(e.target.value)} 
          />
        </div>

        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
          <div className="p-4 bg-slate-50 dark:bg-slate-800/50 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center">
            <span className="text-sm font-bold text-slate-500 dark:text-slate-400">تفاصيل المبيعات</span>
            <button 
              onClick={addRow}
              className="flex items-center gap-1 text-xs bg-slate-800 dark:bg-slate-700 text-white px-3 py-1.5 rounded-lg font-bold hover:bg-slate-700 dark:hover:bg-slate-600 transition-colors"
            >
              <Plus className="w-3.5 h-3.5" /> إضافة صف
            </button>
          </div>

          <div className="p-6 space-y-3">
            {rows.map((row) => (
              <div key={row.tempId} className="flex flex-col sm:flex-row gap-3 items-end sm:items-center animate-in fade-in slide-in-from-right-2 duration-200">
                <div className="flex-1 w-full">
                  <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الصنف المباع</label>
                  <select 
                    className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white"
                    value={row.itemId}
                    onChange={(e) => updateRow(row.tempId, 'itemId', e.target.value)}
                  >
                    <option value="">-- اختر صنفاً --</option>
                    {items.map(i => (
                      <option key={i.id} value={i.id}>{i.name}</option>
                    ))}
                  </select>
                </div>
                <div className="w-full sm:w-32">
                  <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الكمية</label>
                  <input 
                    type="number" 
                    min="1"
                    placeholder="0"
                    className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-2.5 text-center font-mono font-bold outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white"
                    value={row.quantity || ''}
                    onChange={(e) => updateRow(row.tempId, 'quantity', parseInt(e.target.value) || 0)}
                  />
                </div>
                <button 
                  onClick={() => removeRow(row.tempId)}
                  className="p-2.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl transition-colors"
                  title="حذف الصف"
                >
                  <Trash2 className="w-5 h-5" />
                </button>
              </div>
            ))}
          </div>

          <div className="p-6 bg-slate-50 dark:bg-slate-800/30 border-t border-slate-100 dark:border-slate-800 flex justify-end">
            <button 
              onClick={handleSave} 
              disabled={isSaving || rows.every(r => !r.itemId || r.quantity <= 0)} 
              className="flex items-center gap-2 bg-emerald-500 text-white px-8 py-3 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 dark:disabled:bg-slate-700 transition-all hover:scale-[1.02] active:scale-95"
            >
              {isSaving ? <Loader2 className="w-5 h-5 animate-spin" /> : <Save className="w-5 h-5" />} حفظ وإرسال
            </button>
          </div>
        </div>
      </section>

      {/* History Section for Selected Date */}
      <section className="space-y-4">
        <div className="flex items-center justify-between px-2">
          <div className="flex items-center gap-2">
            <History className="w-5 h-5 text-slate-400" />
            <h3 className="text-lg font-bold text-slate-800 dark:text-slate-200">تاريخ مبيعات يوم: {date}</h3>
          </div>
          <span className="text-xs bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-full font-bold text-slate-500 dark:text-slate-400">
            عدد السجلات: {existingSalesForDate.length}
          </span>
        </div>

        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-slate-50 dark:bg-slate-800/50 border-b border-slate-200 dark:border-slate-800 text-slate-500 dark:text-slate-400 text-xs uppercase tracking-wider">
                <tr>
                  <th className="px-6 py-4 font-bold">اسم الصنف</th>
                  <th className="px-6 py-4 font-bold text-center">الكمية المسجلة</th>
                  <th className="px-6 py-4 font-bold w-32 text-center">إجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {existingSalesForDate.length > 0 ? (
                  existingSalesForDate.map((sale) => {
                    const item = items.find(i => i.id === sale.itemId);
                    const isEditing = editingSaleId === sale.id;

                    return (
                      <tr key={sale.id} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                        <td className="px-6 py-4">
                          <span className="font-bold text-slate-700 dark:text-slate-200">{item?.name || 'صنف غير معروف'}</span>
                        </td>
                        <td className="px-6 py-4 text-center">
                          {isEditing ? (
                            <input 
                              type="number" 
                              className="w-24 text-center border-2 border-emerald-500 rounded-lg py-1 font-bold outline-none bg-white dark:bg-slate-800 dark:text-white"
                              value={editQuantity}
                              onChange={(e) => setEditQuantity(parseInt(e.target.value) || 0)}
                              autoFocus
                            />
                          ) : (
                            <span className="font-mono font-bold text-slate-600 dark:text-slate-300 bg-slate-100 dark:bg-slate-800 px-3 py-1 rounded-lg">{sale.quantitySold}</span>
                          )}
                        </td>
                        <td className="px-6 py-4">
                          <div className="flex justify-center gap-2">
                            {isEditing ? (
                              <>
                                <button 
                                  onClick={() => { onUpdateSale(sale.id, editQuantity); setEditingSaleId(null); }}
                                  className="p-2 text-emerald-600 dark:text-emerald-400 hover:bg-emerald-50 dark:hover:bg-emerald-900/20 rounded-lg"
                                >
                                  <Check className="w-4 h-4" />
                                </button>
                                <button 
                                  // Fix: Changed setEditingId to setEditingSaleId
                                  onClick={() => setEditingSaleId(null)}
                                  className="p-2 text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg"
                                >
                                  <X className="w-4 h-4" />
                                </button>
                              </>
                            ) : (
                              <>
                                <button 
                                  onClick={() => startEdit(sale)}
                                  className="p-2 text-blue-500 dark:text-blue-400 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg"
                                >
                                  <Edit3 className="w-4 h-4" />
                                </button>
                                <button 
                                  onClick={() => { if(confirm('حذف هذه العملية؟')) onDeleteSale(sale.id); }}
                                  className="p-2 text-rose-500 dark:text-rose-400 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-lg"
                                >
                                  <Trash2 className="w-4 h-4" />
                                </button>
                              </>
                            )}
                          </div>
                        </td>
                      </tr>
                    );
                  })
                ) : (
                  <tr>
                    <td colSpan={3} className="px-6 py-12 text-center text-slate-400 dark:text-slate-600 italic">
                      <div className="flex flex-col items-center gap-2">
                        <AlertCircle className="w-8 h-8 opacity-20" />
                        <span>لا توجد مبيعات مسجلة لهذا اليوم حتى الآن</span>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </section>
    </div>
  );
};

export default SalesEntryPage;

import React, { useState, useMemo, useCallback } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw, Search, Package, Utensils } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  const [selectedMaterialId, setSelectedMaterialId] = useState<string>('');
  const [selectedItemId, setSelectedItemId] = useState<string>('');

  // Recursive function to flatten consumption from nested recipes
  const getFlattenedConsumption = useCallback((itemId: string, multiplier: number, memo: Record<string, number> = {}, visited: Set<string> = new Set()): Record<string, number> => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe || visited.has(itemId)) return memo;

    visited.add(itemId);

    recipe.ingredients.forEach(ing => {
      const qty = (ing.quantity || 0) * multiplier;
      if (ing.materialId) {
        memo[ing.materialId] = (memo[ing.materialId] || 0) + qty;
      } else if (ing.subItemId) {
        getFlattenedConsumption(ing.subItemId, qty, memo, visited);
      }
    });

    visited.delete(itemId);
    return memo;
  }, [recipes]);

  // Filtered sales based on selected date range and selected item
  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const saleDate = sale.date;
      const dateMatch = saleDate >= startDate && saleDate <= endDate;
      const itemMatch = selectedItemId ? sale.itemId === selectedItemId : true;
      return dateMatch && itemMatch;
    });
  }, [sales, startDate, endDate, selectedItemId]);

  const aggregatedData = useMemo(() => {
    const consumptionMap: Record<string, number> = {};

    filteredSales.forEach(sale => {
      getFlattenedConsumption(sale.itemId, sale.quantitySold, consumptionMap);
    });

    const results = materials.map(m => ({
      name: m.name,
      unit: m.unit,
      total: consumptionMap[m.id] || 0,
      id: m.id
    }));

    return results.filter(item => {
      const matchesMaterial = selectedMaterialId ? item.id === selectedMaterialId : true;
      const hasValue = item.total > 0;
      return matchesMaterial && (selectedMaterialId ? true : hasValue);
    });
  }, [materials, filteredSales, getFlattenedConsumption, selectedMaterialId]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);

      if (item) {
        const flatIngs = getFlattenedConsumption(itemId, 1);

        const ingredients = Object.entries(flatIngs)
          .filter(([matId]) => !selectedMaterialId || matId === selectedMaterialId)
          .map(([matId, qtyPerUnit]) => {
            const mat = materials.find(m => m.id === matId);
            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              // Ensure qtyPerUnit and qtySold are treated as numbers
              consumedQuantity: Number(qtyPerUnit) * Number(qtySold)
            };
          });

        if (ingredients.length > 0) {
          results.push({
            itemName: item.name,
