export const initDb = async () => {
  try {
    await client.batch([
      "CREATE TABLE IF NOT EXISTS restaurants (id TEXT PRIMARY KEY, name TEXT NOT NULL)",
      "CREATE TABLE IF NOT EXISTS material_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_item_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS materials (id TEXT PRIMARY KEY, name TEXT, unit TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_items (id TEXT PRIMARY KEY, name TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS recipes (item_id TEXT, material_id TEXT, sub_item_id TEXT, quantity REAL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales (id TEXT PRIMARY KEY, item_id TEXT, quantity_sold INTEGER, sale_date TEXT, restaurant_id TEXT)"
    ], "write");

    const migrateColumn = async (table: string, column: string, type: string) => {
      try {
        await client.execute(`ALTER TABLE ${table} ADD COLUMN ${column} ${type}`);
      } catch (e: any) {
        // Suppress duplicate column errors
      }
    };

    await migrateColumn("material_groups", "restaurant_id", "TEXT");
    await migrateColumn("sales_item_groups", "restaurant_id", "TEXT");
    await migrateColumn("materials", "restaurant_id", "TEXT");
    await migrateColumn("materials", "group_id", "TEXT");
    await migrateColumn("sales_items", "restaurant_id", "TEXT");
    await migrateColumn("sales_items", "group_id", "TEXT");
    await migrateColumn("recipes", "restaurant_id", "TEXT");
    await migrateColumn("recipes", "sub_item_id", "TEXT");
    await migrateColumn("recipes", "material_id", "TEXT");
    await migrateColumn("sales", "restaurant_id", "TEXT");

    try {
      await client.execute("CREATE INDEX IF NOT EXISTS idx_recipes_item ON recipes(item_id, restaurant_id)");
      await client.execute("CREATE INDEX IF NOT EXISTS idx_sales_restaurant ON sales(restaurant_id)");
    } catch (indexError) {
      console.error("Index creation error:", indexError);
    }

  } catch (error) {
    console.error("Database Init Error:", error);
  }
};

export const db = {
  getRestaurants: async (): Promise<Restaurant[]> => {
    const rs = await client.execute("SELECT * FROM restaurants ORDER BY name");
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string }));
  },
  saveRestaurant: async (r: Restaurant) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO restaurants (id, name) VALUES (?, ?)",
      args: [r.id, r.name]
    });
  },
  deleteRestaurant: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_items WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM materials WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM restaurants WHERE id = ?", args: [id] }
    ], "write");
  },

  cloneRestaurant: async (sourceId: string, newName: string) => {
    const targetId = crypto.randomUUID();

    // 1. Create the new restaurant
    await client.execute({
      sql: "INSERT INTO restaurants (id, name) VALUES (?, ?)",
      args: [targetId, newName]
    });

    // Maps to track old ID -> new ID for related entities
    const materialGroupMap = new Map<string, string>();
    const salesItemGroupMap = new Map<string, string>();
    const materialMap = new Map<string, string>();
    const salesItemMap = new Map<string, string>();

    // 2. Clone Material Groups
    const oldMatGroups = await client.execute({ sql: "SELECT * FROM material_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMatGroups.rows) {
      const newId = crypto.randomUUID();
      materialGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    // 3. Clone Sales Item Groups
    const oldItemGroups = await client.execute({ sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItemGroups.rows) {
      const newId = crypto.randomUUID();
      salesItemGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    // 4. Clone Materials
    const oldMaterials = await client.execute({ sql: "SELECT * FROM materials WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMaterials.rows) {
      const newId = crypto.randomUUID();
      materialMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? materialGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [newId, row.name, row.unit, newGroupId, targetId]
      });
    }

    // 5. Clone Sales Items
    const oldItems = await client.execute({ sql: "SELECT * FROM sales_items WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItems.rows) {
      const newId = crypto.randomUUID();
      salesItemMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? salesItemGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO sales_items (id, name, group_id, restaurant_id) VALUES (?, ?, ?, ?)",
        args: [newId, row.name, newGroupId, targetId]
      });
    }

    // 6. Clone Recipes
    const oldRecipes = await client.execute({ sql: "SELECT * FROM recipes WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldRecipes.rows) {
      const newItemId = salesItemMap.get(row.item_id as string);
      const newMatId = row.material_id ? materialMap.get(row.material_id as string) : null;
      const newSubItemId = row.sub_item_id ? salesItemMap.get(row.sub_item_id as string) : null;

      if (newItemId) {
        await client.execute({
          sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
          args: [newItemId, newMatId, newSubItemId, row.quantity, targetId]
        });
      }
    }

    return { id: targetId, name: newName };
  },

  // Material Groups
  getMaterialGroups: async (restaurantId: string): Promise<MaterialGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM material_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveMaterialGroup: async (g: MaterialGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteMaterialGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE materials SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Sales Item Groups
  getSalesItemGroups: async (restaurantId: string): Promise<SalesItemGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveSalesItemGroup: async (g: SalesItemGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteSalesItemGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE sales_items SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Materials
  getMaterials: async (restaurantId: string): Promise<Material[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM materials WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string, 
      unit: row.unit as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [m.id, m.name, m.unit, m.groupId || null, m.restaurantId]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (restaurantId: string): Promise<SalesItem[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_items WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name, group_id, restaurant_id) VALUES (?, ?, ?, ?)",
      args: [i.id, i.name, i.groupId || null, i.restaurantId]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (restaurantId: string): Promise<Recipe[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM recipes WHERE restaurant_id = ?",
      args: [restaurantId]
    });
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [], restaurantId: row.restaurant_id as string };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string || undefined,
        subItemId: row.sub_item_id as string || undefined,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ? AND restaurant_id = ?", args: [recipe.itemId, recipe.restaurantId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [
          recipe.itemId, 
          ing.materialId || null, 
          ing.subItemId || null, 
          ing.quantity, 
          recipe.restaurantId
        ]
      }))
    ];
    await client.batch(queries, "write");
  },

  // Sales
  getSales: async (restaurantId: string): Promise<SaleEntry[]> => {
    const rs = await client.execute({
      sql: "SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date, restaurant_id as restaurantId FROM sales WHERE restaurant_id = ? ORDER BY sale_date DESC",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({
      id: row.id as string,
      itemId: row.itemId as string,
      quantitySold: row.quantitySold as number,
      date: row.date as string,
      restaurantId: row.restaurantId as string
    }));
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date, s.restaurantId]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { ChefHat, Loader2, CheckCircle2, AlertCircle, X, Store, Settings, Plus, Trash2, ArrowRight, Copy } from 'lucide-react';
import { 
  Material, SalesItem, Recipe, SaleEntry,
  MaterialGroup, SalesItemGroup, Restaurant
} from './types';
import { db, initDb } from './db';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';
import QuickQueryPage from './components/QuickQueryPage';

interface Toast {
  id: string;
  message: string;
  type: 'success' | 'error';
}

const App: React.FC = () => {
  const [currentRestaurant, setCurrentRestaurant] = useState<Restaurant | null>(null);
  const [isManagerMode, setIsManagerMode] = useState(false);
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [newRestName, setNewRestName] = useState('');
  const [isCloning, setIsCloning] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports' | 'query'>('items');
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toasts, setToasts] = useState<Toast[]>([]);

  const [materials, setMaterials] = useState<Material[]>([]);
  const [materialGroups, setMaterialGroups] = useState<MaterialGroup[]>([]);
  const [salesItems, setSalesItems] = useState<SalesItem[]>([]);
  const [salesItemGroups, setSalesItemGroups] = useState<SalesItemGroup[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [sales, setSales] = useState<SaleEntry[]>([]);

  const addToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    const id = crypto.randomUUID();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  }, []);

  // Initial DB Load
  useEffect(() => {
    const init = async () => {
      await initDb();
      const rests = await db.getRestaurants();
      setRestaurants(rests);
      setIsLoading(false);
    };
    init();
  }, []);

  // Data load per Restaurant
  useEffect(() => {
    if (!currentRestaurant) return;

    const loadData = async () => {
      setIsLoading(true);
      try {
        const [mats, matGrps, items, itemGrps, recs, sls] = await Promise.all([
          db.getMaterials(currentRestaurant.id),
          db.getMaterialGroups(currentRestaurant.id),
          db.getItems(currentRestaurant.id),
          db.getSalesItemGroups(currentRestaurant.id),
          db.getRecipes(currentRestaurant.id),
          db.getSales(currentRestaurant.id)
        ]);
        setMaterials(mats);
        setMaterialGroups(matGrps);
        setSalesItems(items);
        setSalesItemGroups(itemGrps);
        setRecipes(recs);
        setSales(sls);
      } catch (error) {
        addToast("فشل تحميل بيانات المطعم", "error");
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [currentRestaurant, addToast]);

  const handleCreateRestaurant = async () => {
    if (!newRestName.trim()) return;
    const r: Restaurant = { id: crypto.randomUUID(), name: newRestName.trim() };
    await db.saveRestaurant(r);
    setRestaurants(prev => [...prev, r]);
    setNewRestName('');
    addToast(`تم إنشاء مطعم "${r.name}" بنجاح`);
  };

  const handleCloneRestaurant = async (id: string, name: string) => {
    const newName = prompt(`أدخل اسم المطعم الجديد المستنسخ من "${name}":`, `${name} - نسخة`);
    if (!newName || !newName.trim()) return;

    setIsCloning(id);
    try {
      const cloned = await db.cloneRestaurant(id, newName.trim());
      setRestaurants(prev => [...prev, cloned]);
      addToast(`تم استنساخ "${name}" إلى "${cloned.name}" بنجاح`);
    } catch (err) {
      addToast("فشل استنساخ المطعم", "error");
    } finally {
      setIsCloning(null);
    }
  };

  const handleDeleteRestaurant = async (id: string) => {
    if (confirm("سيتم حذف كافة بيانات المطعم بشكل نهائي! هل أنت متأكد؟")) {
      await db.deleteRestaurant(id);
      setRestaurants(prev => prev.filter(r => r.id !== id));
      addToast("تم حذف المطعم وبياناته");
    }
  };

  const handleAddMaterialGroup = async (g: Omit<MaterialGroup, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const group = { ...g, restaurantId: currentRestaurant.id };
    await db.saveMaterialGroup(group);
    setMaterialGroups(prev => [...prev, group]);
  };
  const handleDeleteMaterialGroup = async (id: string) => {
    await db.deleteMaterialGroup(id);
    setMaterialGroups(prev => prev.filter(g => g.id !== id));
    setMaterials(prev => prev.map(m => m.groupId === id ? { ...m, groupId: undefined } : m));
  };

  const handleAddSalesItemGroup = async (g: Omit<SalesItemGroup, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const group = { ...g, restaurantId: currentRestaurant.id };
    await db.saveSalesItemGroup(group);
    setSalesItemGroups(prev => [...prev, group]);
  };
  const handleDeleteSalesItemGroup = async (id: string) => {
    await db.deleteSalesItemGroup(id);
    setSalesItemGroups(prev => prev.filter(g => g.id !== id));
    setSalesItems(prev => prev.map(i => i.groupId === id ? { ...i, groupId: undefined } : i));
  };

  const handleAddMaterial = async (m: Omit<Material, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const mat = { ...m, restaurantId: currentRestaurant.id };
    await db.saveMaterial(mat);
    setMaterials(prev => [...prev, mat]);
  };
  const handleUpdateMaterial = async (m: Omit<Material, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const mat: Material = { ...m, restaurantId: currentRestaurant.id };
    await db.saveMaterial(mat);
    setMaterials(prev => prev.map(old => old.id === m.id ? mat : old));
  };
  const handleDeleteMaterial = async (id: string) => {
    await db.deleteMaterial(id);
    setMaterials(prev => prev.filter(m => m.id !== id));
  };

  const handleAddItem = async (i: Omit<SalesItem, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const item = { ...i, restaurantId: currentRestaurant.id };
    await db.saveItem(item);
    setSalesItems(prev => [...prev, item]);
  };
  const handleUpdateItem = async (i: Omit<SalesItem, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const item: SalesItem = { ...i, restaurantId: currentRestaurant.id };
    await db.saveItem(item);
    setSalesItems(prev => prev.map(old => old.id === i.id ? item : old));
  };
  const handleDeleteItem = async (id: string) => {
    await db.deleteItem(id);
    setSalesItems(prev => prev.filter(i => i.id !== id));
  };

  const handleSaveRecipe = async (r: Omit<Recipe, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const recipe = { ...r, restaurantId: currentRestaurant.id };
    await db.saveRecipe(recipe);
    setRecipes(prev => {
      const exists = prev.some(old => old.itemId === recipe.itemId);
      return exists ? prev.map(old => old.itemId === recipe.itemId ? recipe : old) : [...prev, recipe];
    });
  };

  const handleSaveSales = async (entries: Omit<SaleEntry, 'restaurantId'>[]) => {
    if (!currentRestaurant) return;
    const salesWithId = entries.map(e => ({ ...e, restaurantId: currentRestaurant.id }));
    await db.saveSales(salesWithId);
    setSales(prev => [...salesWithId, ...prev]);
  };

  const handleDeleteSale = async (id: string) => {
    await db.deleteSale(id);
    setSales(prev => prev.filter(s => s.id !== id));
  };

  if (isLoading && !currentRestaurant) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <Loader2 className="w-12 h-12 text-emerald-500 animate-spin" />
        <p className="mt-4 font-bold text-slate-600">جاري تهيئة النظام...</p>
      </div>
    );
  }

  // --- Restaurant Selection Screen ---
  if (!currentRestaurant) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4" dir="rtl">
        <div className="max-w-4xl w-full">
          <div className="text-center mb-10">
            <ChefHat className="w-16 h-16 text-emerald-500 mx-auto mb-4" />
            <h1 className="text-3xl font-bold text-slate-800">CulinaTrack</h1>
            <p className="text-slate-500 mt-2">نظام إدارة استهلاك المواد الخام للمطاعم</p>
          </div>

          {!isManagerMode ? (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {restaurants.map(r => (
                  <button
                    key={r.id}
                    onClick={() => setCurrentRestaurant(r)}
                    className="bg-white p-8 rounded-3xl shadow-sm border-2 border-transparent hover:border-emerald-500 hover:shadow-xl hover:-translate-y-1 transition-all group text-right"
                  >
                    <div className="bg-emerald-50 w-12 h-12 rounded-2xl flex items-center justify-center mb-4 group-hover:bg-emerald-500 transition-colors">
                      <Store className="w-6 h-6 text-emerald-500 group-hover:text-white" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800">{r.name}</h3>
                    <p className="text-slate-400 text-sm mt-1 flex items-center gap-1">دخول للنظام <ArrowRight className="w-3 h-3" /></p>
                  </button>
                ))}

                {restaurants.length === 0 && (
                  <div className="col-span-full py-20 text-center border-2 border-dashed rounded-3xl text-slate-400">
                    لا يوجد مطاعم مسجلة حالياً
                  </div>
                )}
              </div>
              <button 
                onClick={() => setIsManagerMode(true)}
                className="w-full flex items-center justify-center gap-2 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-bold transition-colors"
              >
                <Settings className="w-5 h-5" /> لوحة تحكم المدير (إضافة واستنساخ مطاعم)
              </button>
            </div>
          ) : (
            <div className="bg-white p-8 rounded-3xl shadow-xl animate-in zoom-in duration-300">
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-bold text-slate-800">إدارة المطاعم</h2>
                <button onClick={() => setIsManagerMode(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
              </div>

              <div className="space-y-6">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="اسم المطعم الجديد" 
                    className="flex-1 border rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-emerald-500"
                    value={newRestName}
                    onChange={(e) => setNewRestName(e.target.value)}
                  />
                  <button 
                    onClick={handleCreateRestaurant}
                    className="bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold hover:bg-emerald-600"
                  >
                    إضافة مطعم
                  </button>
                </div>

                <div className="divide-y">
                  {restaurants.map(r => (
                    <div key={r.id} className="py-4 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <Store className="w-5 h-5 text-slate-400" />
                        <span className="font-bold text-slate-700">{r.name}</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleCloneRestaurant(r.id, r.name)}
                          disabled={isCloning === r.id}
                          className="flex items-center gap-1 px-3 py-1.5 text-blue-500 hover:bg-blue-50 rounded-lg transition-colors text-sm font-bold disabled:opacity-50"
                          title="استنساخ المطعم"
                        >
                          {isCloning === r.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Copy className="w-4 h-4" />}
                          استنساخ
                        </button>
                        <button 
                          onClick={() => handleDeleteRestaurant(r.id)}
                          className="p-2 text-rose-400 hover:bg-rose-50 hover:text-rose-600 rounded-lg transition-colors"
                          title="حذف المطعم"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'materials':
        return (
          <MaterialsPage 
            materials={materials}
            groups={materialGroups} 
            onAdd={handleAddMaterial} 
            onUpdate={handleUpdateMaterial} 
            onDelete={handleDeleteMaterial}
            onAddGroup={handleAddMaterialGroup}
            onUpdateGroup={(g) => db.saveMaterialGroup({ ...g, restaurantId: currentRestaurant.id })}
            onDeleteGroup={handleDeleteMaterialGroup}
          />
        );
      case 'items':
        return (
          <SalesItemsPage 
            items={salesItems}
            groups={salesItemGroups}
            onAdd={handleAddItem} 
            onUpdate={handleUpdateItem} 
            onDelete={handleDeleteItem} 
            onAddGroup={handleAddSalesItemGroup}
            onUpdateGroup={(g) => db.saveSalesItemGroup({ ...g, restaurantId: currentRestaurant.id })}
            onDeleteGroup={handleDeleteSalesItemGroup}
          />
        );
      case 'recipes':
        return (
          <RecipeBuilderPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
            onSave={handleSaveRecipe} 
          />
        );
      case 'sales':
        return (
          <SalesEntryPage 
            items={salesItems} 
            sales={sales} 
            onSave={handleSaveSales} 
            onDeleteSale={handleDeleteSale}
            onUpdateSale={db.updateSale}
          />
        );
      case 'reports':
        return (
          <ReportsPage 
            materials={materials} 
            items={salesItems} 
            recipes={recipes} 
            sales={sales} 
          />
        );
      case 'query':
        return (
          <QuickQueryPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 overflow-x-hidden" dir="rtl">
      {isLoading && currentRestaurant && (
        <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[200] flex items-center justify-center">
          <Loader2 className="w-10 h-10 text-emerald-500 animate-spin" />
        </div>
      )}

      <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[300] flex flex-col gap-3 pointer-events-none">
        {toasts.map(toast => (
          <div 
            key={toast.id} 
            className={`flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border pointer-events-auto animate-in slide-in-from-top-4 duration-300 ${
              toast.type === 'success' ? 'bg-white border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'
            }`}
          >
            {toast.type === 'success' ? <CheckCircle2 className="w-5 h-5 text-emerald-500" /> : <AlertCircle className="w-5 h-5 text-rose-500" />}
            <span className="font-bold text-sm">{toast.message}</span>
            <button onClick={() => setToasts(prev => prev.filter(t => t.id !== toast.id))} className="mr-4 text-slate-400 hover:text-slate-600">
              <X className="w-4 h-4" />
            </button>
          </div>
        ))}
      </div>

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab: any) => setActiveTab(tab)} 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
        restaurantName={currentRestaurant.name}
        onExit={() => setCurrentRestaurant(null)}
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          activeTab={activeTab} 
          onOpenSidebar={() => setIsSidebarOpen(true)}
        />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

