export const initDb = async () => {
  try {
    // 1. Create tables if they don't exist
    await client.batch([
      "CREATE TABLE IF NOT EXISTS restaurants (id TEXT PRIMARY KEY, name TEXT NOT NULL)",
      "CREATE TABLE IF NOT EXISTS material_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_item_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS materials (id TEXT PRIMARY KEY, name TEXT, unit TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_items (id TEXT PRIMARY KEY, name TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS recipes (item_id TEXT, material_id TEXT, sub_item_id TEXT, quantity REAL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales (id TEXT PRIMARY KEY, item_id TEXT, quantity_sold INTEGER, sale_date TEXT, restaurant_id TEXT)"
    ], "write");

    // 2. Migration: Add columns if they were missing from a previous schema version
    const migrateColumn = async (table: string, column: string, type: string) => {
      try {
        await client.execute(`ALTER TABLE ${table} ADD COLUMN ${column} ${type}`);
      } catch (e: any) {
        if (!e.message?.toLowerCase().includes("duplicate column name")) {
        }
      }
    };

    await migrateColumn("material_groups", "restaurant_id", "TEXT");
    await migrateColumn("sales_item_groups", "restaurant_id", "TEXT");
    await migrateColumn("materials", "restaurant_id", "TEXT");
    await migrateColumn("materials", "group_id", "TEXT");
    await migrateColumn("sales_items", "restaurant_id", "TEXT");
    await migrateColumn("sales_items", "group_id", "TEXT");
    await migrateColumn("recipes", "restaurant_id", "TEXT");
    await migrateColumn("recipes", "sub_item_id", "TEXT");
    await migrateColumn("recipes", "material_id", "TEXT");
    await migrateColumn("sales", "restaurant_id", "TEXT");

    // 3. Create indices for performance
    try {
      await client.execute("CREATE INDEX IF NOT EXISTS idx_recipes_item ON recipes(item_id, restaurant_id)");
      await client.execute("CREATE INDEX IF NOT EXISTS idx_sales_restaurant ON sales(restaurant_id)");
    } catch (indexError) {
      console.error("Index creation error (likely missing columns still):", indexError);
    }

  } catch (error) {
    console.error("Database Init Error:", error);
  }
};

export const db = {
  // Restaurants
  getRestaurants: async (): Promise<Restaurant[]> => {
    const rs = await client.execute("SELECT * FROM restaurants ORDER BY name");
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string }));
  },
  saveRestaurant: async (r: Restaurant) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO restaurants (id, name) VALUES (?, ?)",
      args: [r.id, r.name]
    });
  },
  deleteRestaurant: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_items WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM materials WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM restaurants WHERE id = ?", args: [id] }
    ], "write");
  },

  // Clone Restaurant Implementation
  cloneRestaurant: async (sourceId: string, newName: string) => {
    const targetId = crypto.randomUUID();

    await client.execute({
      sql: "INSERT INTO restaurants (id, name) VALUES (?, ?)",
      args: [targetId, newName]
    });

    const materialGroupMap = new Map<string, string>();
    const salesItemGroupMap = new Map<string, string>();
    const materialMap = new Map<string, string>();
    const salesItemMap = new Map<string, string>();

    const oldMatGroups = await client.execute({ sql: "SELECT * FROM material_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMatGroups.rows) {
      const newId = crypto.randomUUID();
      materialGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    const oldItemGroups = await client.execute({ sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItemGroups.rows) {
      const newId = crypto.randomUUID();
      salesItemGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    const oldMaterials = await client.execute({ sql: "SELECT * FROM materials WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMaterials.rows) {
      const newId = crypto.randomUUID();
      materialMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? materialGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [newId, row.name, row.unit, newGroupId, targetId]
      });
    }

    const oldItems = await client.execute({ sql: "SELECT * FROM sales_items WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItems.rows) {
      const newId = crypto.randomUUID();
      salesItemMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? salesItemGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO sales_items (id, name, group_id, restaurant_id) VALUES (?, ?, ?, ?)",
        args: [newId, row.name, newGroupId, targetId]
      });
    }

    const oldRecipes = await client.execute({ sql: "SELECT * FROM recipes WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldRecipes.rows) {
      const newItemId = salesItemMap.get(row.item_id as string);
      const newMatId = row.material_id ? materialMap.get(row.material_id as string) : null;
      const newSubItemId = row.sub_item_id ? salesItemMap.get(row.sub_item_id as string) : null;

      if (newItemId) {
        await client.execute({
          sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
          args: [newItemId, newMatId, newSubItemId, row.quantity, targetId]
        });
      }
    }

    return { id: targetId, name: newName };
  },

  // Material Groups
  getMaterialGroups: async (restaurantId: string): Promise<MaterialGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM material_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveMaterialGroup: async (g: MaterialGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteMaterialGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE materials SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Sales Item Groups
  getSalesItemGroups: async (restaurantId: string): Promise<SalesItemGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveSalesItemGroup: async (g: SalesItemGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteSalesItemGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE sales_items SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Materials
  getMaterials: async (restaurantId: string): Promise<Material[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM materials WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string, 
      unit: row.unit as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [m.id, m.name, m.unit, m.groupId || null, m.restaurantId]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (restaurantId: string): Promise<SalesItem[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_items WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name, group_id, restaurant_id) VALUES (?, ?, ?, ?)",
      args: [i.id, i.name, i.groupId || null, i.restaurantId]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (restaurantId: string): Promise<Recipe[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM recipes WHERE restaurant_id = ?",
      args: [restaurantId]
    });
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [], restaurantId: row.restaurant_id as string };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string || undefined,
        subItemId: row.sub_item_id as string || undefined,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ? AND restaurant_id = ?", args: [recipe.itemId, recipe.restaurantId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [
          recipe.itemId, 
          ing.materialId || null, 
          ing.subItemId || null, 
          ing.quantity, 
          recipe.restaurantId
        ]
      }))
    ];
    await client.batch(queries, "write");
  },

  // Sales
  getSales: async (restaurantId: string): Promise<SaleEntry[]> => {
    const rs = await client.execute({
      sql: "SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date, restaurant_id as restaurantId FROM sales WHERE restaurant_id = ? ORDER BY sale_date DESC",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({
      id: row.id as string,
      itemId: row.itemId as string,
      quantitySold: row.quantitySold as number,
      date: row.date as string,
      restaurantId: row.restaurantId as string
    }));
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date, s.restaurantId]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Calculator, Save, Package, UtensilsCrossed, ArrowRightLeft, Info, ChefHat, Printer } from 'lucide-react';
import { SalesItem, Material, Recipe, RecipeIngredient } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
  onSave: (recipe: Omit<Recipe, 'restaurantId'>) => Promise<void>;
}

// Local interface to handle string inputs for decimals during editing
interface LocalRecipeIngredient extends Omit<RecipeIngredient, 'quantity'> {
  quantity: string | number;
}

const RecipeBuilderPage: React.FC<Props> = ({ items, materials, recipes, onSave }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [localIngredients, setLocalIngredients] = useState<LocalRecipeIngredient[]>([]);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const existing = recipes.find(r => r.itemId === selectedItemId);
    setLocalIngredients(existing ? existing.ingredients.map(i => ({...i})) : []);
  }, [selectedItemId, recipes]);

  const getSubItemRecipe = (subItemId: string) => {
    const recipe = recipes.find(r => r.itemId === subItemId);
    if (!recipe) return null;
    return recipe.ingredients.map(ing => {
      const name = ing.materialId 
        ? materials.find(m => m.id === ing.materialId)?.name 
        : items.find(i => i.id === ing.subItemId)?.name;
      return { name, quantity: ing.quantity };
    });
  };

  const addIngredient = (type: 'material' | 'item') => {
    if (!selectedItemId) return;

    if (type === 'material') {
      if (materials.length === 0) return;
      setLocalIngredients([...localIngredients, { materialId: materials[0].id, quantity: '' }]);
    } else {
      if (items.length === 0) return;
      // Filter out the selected item itself to prevent circular reference
      const otherItems = items.filter(i => i.id !== selectedItemId);
      if (otherItems.length === 0) return;
      setLocalIngredients([...localIngredients, { subItemId: otherItems[0].id, quantity: '' }]);
    }
  };

  const updateIngredient = (idx: number, field: keyof LocalRecipeIngredient, value: any) => {
    const next = [...localIngredients];
    // @ts-ignore - dynamic assignment
    next[idx] = { ...next[idx], [field]: value };

    // Ensure if we update materialId, subItemId is cleared and vice versa
    if (field === 'materialId') delete next[idx].subItemId;
    if (field === 'subItemId') delete next[idx].materialId;

    setLocalIngredients(next);
  };

  const toggleType = (idx: number) => {
    const current = localIngredients[idx];
    const next = [...localIngredients];
    if (current.materialId) {
      const otherItems = items.filter(i => i.id !== selectedItemId);
      next[idx] = { subItemId: otherItems[0]?.id || '', quantity: current.quantity };
    } else {
      next[idx] = { materialId: materials[0]?.id || '', quantity: current.quantity };
    }
    setLocalIngredients(next);
  };

  const removeIngredient = (idx: number) => {
    setLocalIngredients(localIngredients.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!selectedItemId) return;
    setIsSaving(true);

    // Parse strings back to numbers for saving
    const ingredientsToSave: RecipeIngredient[] = localIngredients.map(ing => ({
      materialId: ing.materialId,
      subItemId: ing.subItemId,
      quantity: typeof ing.quantity === 'string' ? parseFloat(ing.quantity) || 0 : ing.quantity
    }));

    await onSave({ itemId: selectedItemId, ingredients: ingredientsToSave });
    setIsSaving(false);
  };

  const handlePrint = () => {
    window.print();
  };

  const selectedItemName = items.find(i => i.id === selectedItemId)?.name;

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      {/* Interactive View (Hidden on Print) */}
      <div className="print:hidden space-y-6">
        <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
          <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mb-2">اختر الصنف الرئيسي لتعديل وصفته:</label>
          <select
            className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium transition-colors"
            value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}
          >
            <option value="">-- اختر صنفاً --</option>
            {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
          </select>
        </div>

        {selectedItemId && (
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-2 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row justify-between items-center bg-slate-50/50 dark:bg-slate-800/50 gap-4">
              <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2">
                وصفة: <span className="text-emerald-600 dark:text-emerald-400">{selectedItemName}</span>
              </h3>
              <div className="flex flex-wrap gap-2">
                 <button onClick={() => addIngredient('material')} className="flex items-center gap-2 text-xs bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-colors"><Package className="w-3.5 h-3.5" /> إضافة خامة</button>
                 <button onClick={() => addIngredient('item')} className="flex items-center gap-2 text-xs bg-blue-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-blue-700 transition-colors"><ChefHat className="w-3.5 h-3.5" /> إضافة صنف مجهز</button>
                 <button onClick={handlePrint} className="flex items-center gap-2 text-xs bg-slate-100 text-slate-700 border border-slate-300 px-4 py-2 rounded-xl font-bold hover:bg-slate-200 transition-colors"><Printer className="w-3.5 h-3.5" /> طباعة / PDF</button>
                 <button onClick={handleSave} disabled={isSaving} className="flex items-center gap-2 text-sm bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 transition-all hover:scale-105 active:scale-95"><Save className="w-4 h-4" /> {isSaving ? 'جاري الحفظ...' : 'حفظ الوصفة'}</button>
              </div>
            </div>
            <div className="p-6 space-y-4">
              {localIngredients.length === 0 ? (
                <div className="text-center py-12 text-slate-400 dark:text-slate-600"><Calculator className="w-12 h-12 mx-auto mb-3 opacity-20" /><p>لا توجد مكونات في هذه الوصفة. ابدأ بإضافة خامات أو أصناف مجهزة.</p></div>
              ) : (
                localIngredients.map((ing, idx) => {
                  const isSubItem = !!ing.subItemId;
                  const subRecipe = isSubItem ? getSubItemRecipe(ing.subItemId!) : null;

                  return (
                    <div key={idx} className={`flex flex-col md:flex-row gap-4 items-start p-4 rounded-xl border transition-all ${
                      isSubItem 
                        ? 'bg-blue-50/40 border-blue-200 dark:bg-blue-900/10 dark:border-blue-800/40 shadow-sm' 
                        : 'bg-slate-50/50 border-slate-100 dark:bg-slate-800/30 dark:border-slate-800/50'
                    }`}>
                      <div className="flex-1 w-full">
                        <div className="flex items-center justify-between mb-1 mr-1">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1.5">
                            {isSubItem ? (
                              <span className="flex items-center gap-1 text-blue-600 dark:text-blue-400">
                                <ChefHat className="w-3.5 h-3.5" /> صنف مجهز (وصفة فرعية)
                              </span>
                            ) : (
                              <span className="flex items-center gap-1">
                                <Package className="w-3.5 h-3.5 text-slate-500" /> خامة أساسية
                              </span>
                            )}
                          </label>
                          <button onClick={() => toggleType(idx)} className="text-[10px] text-emerald-500 hover:underline flex items-center gap-1 font-bold">
                            <ArrowRightLeft className="w-3 h-3" /> تبديل النوع
                          </button>
                        </div>
                        <div className="flex gap-2 items-center">
                          <select 
                            className={`w-full border rounded-xl px-4 py-2.5 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 transition-colors ${
                              isSubItem ? 'border-blue-200 dark:border-blue-800 font-bold' : 'border-slate-200 dark:border-slate-700'
                            }`} 
                            value={isSubItem ? ing.subItemId : ing.materialId} 
                            onChange={(e) => updateIngredient(idx, isSubItem ? 'subItemId' : 'materialId', e.target.value)}
                          >
                            {isSubItem ? (
                              items.filter(i => i.id !== selectedItemId).map(i => <option key={i.id} value={i.id}>{i.name}</option>)
                            ) : (
                              materials.map(m => <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>)
                            )}
                          </select>

                          {isSubItem && (
                            <div className="relative group">
                              <div className="p-2 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg cursor-help hover:bg-blue-200 transition-colors">
                                <Info className="w-4 h-4" />
