export const initDb = async () => {
  try {
    // 1. Create tables if they don't exist
    await client.batch([
      "CREATE TABLE IF NOT EXISTS restaurants (id TEXT PRIMARY KEY, name TEXT NOT NULL)",
      "CREATE TABLE IF NOT EXISTS material_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_item_groups (id TEXT PRIMARY KEY, name TEXT NOT NULL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS materials (id TEXT PRIMARY KEY, name TEXT, unit TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales_items (id TEXT PRIMARY KEY, name TEXT, unit TEXT, group_id TEXT, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS recipes (item_id TEXT, material_id TEXT, sub_item_id TEXT, quantity REAL, restaurant_id TEXT)",
      "CREATE TABLE IF NOT EXISTS sales (id TEXT PRIMARY KEY, item_id TEXT, quantity_sold INTEGER, sale_date TEXT, restaurant_id TEXT)"
    ], "write");

    // 2. Migration: Add columns if they were missing from a previous schema version
    const migrateColumn = async (table: string, column: string, type: string) => {
      try {
        await client.execute(`ALTER TABLE ${table} ADD COLUMN ${column} ${type}`);
      } catch (e: any) {
        if (!e.message?.toLowerCase().includes("duplicate column name")) {
        }
      }
    };

    await migrateColumn("material_groups", "restaurant_id", "TEXT");
    await migrateColumn("sales_item_groups", "restaurant_id", "TEXT");
    await migrateColumn("materials", "restaurant_id", "TEXT");
    await migrateColumn("materials", "group_id", "TEXT");
    await migrateColumn("sales_items", "restaurant_id", "TEXT");
    await migrateColumn("sales_items", "group_id", "TEXT");
    await migrateColumn("sales_items", "unit", "TEXT"); // New column for Unit
    await migrateColumn("recipes", "restaurant_id", "TEXT");
    await migrateColumn("recipes", "sub_item_id", "TEXT");
    await migrateColumn("recipes", "material_id", "TEXT");
    await migrateColumn("sales", "restaurant_id", "TEXT");

    // 3. Create indices for performance
    try {
      await client.execute("CREATE INDEX IF NOT EXISTS idx_recipes_item ON recipes(item_id, restaurant_id)");
      await client.execute("CREATE INDEX IF NOT EXISTS idx_sales_restaurant ON sales(restaurant_id)");
    } catch (indexError) {
      console.error("Index creation error (likely missing columns still):", indexError);
    }

  } catch (error) {
    console.error("Database Init Error:", error);
  }
};

export const db = {
  // Restaurants
  getRestaurants: async (): Promise<Restaurant[]> => {
    const rs = await client.execute("SELECT * FROM restaurants ORDER BY name");
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string }));
  },
  saveRestaurant: async (r: Restaurant) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO restaurants (id, name) VALUES (?, ?)",
      args: [r.id, r.name]
    });
  },
  deleteRestaurant: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_items WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM materials WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE restaurant_id = ?", args: [id] },
      { sql: "DELETE FROM restaurants WHERE id = ?", args: [id] }
    ], "write");
  },

  // Clone Restaurant Implementation
  cloneRestaurant: async (sourceId: string, newName: string) => {
    const targetId = crypto.randomUUID();

    await client.execute({
      sql: "INSERT INTO restaurants (id, name) VALUES (?, ?)",
      args: [targetId, newName]
    });

    const materialGroupMap = new Map<string, string>();
    const salesItemGroupMap = new Map<string, string>();
    const materialMap = new Map<string, string>();
    const salesItemMap = new Map<string, string>();

    const oldMatGroups = await client.execute({ sql: "SELECT * FROM material_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMatGroups.rows) {
      const newId = crypto.randomUUID();
      materialGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    const oldItemGroups = await client.execute({ sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItemGroups.rows) {
      const newId = crypto.randomUUID();
      salesItemGroupMap.set(row.id as string, newId);
      await client.execute({
        sql: "INSERT INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
        args: [newId, row.name, targetId]
      });
    }

    const oldMaterials = await client.execute({ sql: "SELECT * FROM materials WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldMaterials.rows) {
      const newId = crypto.randomUUID();
      materialMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? materialGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [newId, row.name, row.unit, newGroupId, targetId]
      });
    }

    const oldItems = await client.execute({ sql: "SELECT * FROM sales_items WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldItems.rows) {
      const newId = crypto.randomUUID();
      salesItemMap.set(row.id as string, newId);
      const newGroupId = row.group_id ? salesItemGroupMap.get(row.group_id as string) : null;
      await client.execute({
        sql: "INSERT INTO sales_items (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [newId, row.name, row.unit || null, newGroupId, targetId]
      });
    }

    const oldRecipes = await client.execute({ sql: "SELECT * FROM recipes WHERE restaurant_id = ?", args: [sourceId] });
    for (const row of oldRecipes.rows) {
      const newItemId = salesItemMap.get(row.item_id as string);
      const newMatId = row.material_id ? materialMap.get(row.material_id as string) : null;
      const newSubItemId = row.sub_item_id ? salesItemMap.get(row.sub_item_id as string) : null;

      if (newItemId) {
        await client.execute({
          sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
          args: [newItemId, newMatId, newSubItemId, row.quantity, targetId]
        });
      }
    }

    return { id: targetId, name: newName };
  },

  // Material Groups
  getMaterialGroups: async (restaurantId: string): Promise<MaterialGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM material_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveMaterialGroup: async (g: MaterialGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO material_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteMaterialGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE materials SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM material_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Sales Item Groups
  getSalesItemGroups: async (restaurantId: string): Promise<SalesItemGroup[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_item_groups WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ id: row.id as string, name: row.name as string, restaurantId: row.restaurant_id as string }));
  },
  saveSalesItemGroup: async (g: SalesItemGroup) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_item_groups (id, name, restaurant_id) VALUES (?, ?, ?)",
      args: [g.id, g.name, g.restaurantId]
    });
  },
  deleteSalesItemGroup: async (id: string) => {
    await client.batch([
      { sql: "UPDATE sales_items SET group_id = NULL WHERE group_id = ?", args: [id] },
      { sql: "DELETE FROM sales_item_groups WHERE id = ?", args: [id] }
    ], "write");
  },

  // Materials
  getMaterials: async (restaurantId: string): Promise<Material[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM materials WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string, 
      unit: row.unit as string,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveMaterial: async (m: Material) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO materials (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [m.id, m.name, m.unit, m.groupId || null, m.restaurantId]
    });
  },
  deleteMaterial: async (id: string) => {
    await client.execute({ sql: "DELETE FROM materials WHERE id = ?", args: [id] });
  },

  // Sales Items
  getItems: async (restaurantId: string): Promise<SalesItem[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM sales_items WHERE restaurant_id = ? ORDER BY name",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({ 
      id: row.id as string, 
      name: row.name as string,
      unit: row.unit as string || undefined,
      groupId: row.group_id as string || undefined,
      restaurantId: row.restaurant_id as string
    }));
  },
  saveItem: async (i: SalesItem) => {
    await client.execute({
      sql: "INSERT OR REPLACE INTO sales_items (id, name, unit, group_id, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [i.id, i.name, i.unit || null, i.groupId || null, i.restaurantId]
    });
  },
  deleteItem: async (id: string) => {
    await client.batch([
      { sql: "DELETE FROM sales_items WHERE id = ?", args: [id] },
      { sql: "DELETE FROM recipes WHERE item_id = ?", args: [id] }
    ], "write");
  },

  // Recipes
  getRecipes: async (restaurantId: string): Promise<Recipe[]> => {
    const rs = await client.execute({
      sql: "SELECT * FROM recipes WHERE restaurant_id = ?",
      args: [restaurantId]
    });
    const grouped: Record<string, Recipe> = {};
    rs.rows.forEach(row => {
      const itemId = row.item_id as string;
      if (!grouped[itemId]) grouped[itemId] = { itemId, ingredients: [], restaurantId: row.restaurant_id as string };
      grouped[itemId].ingredients.push({
        materialId: row.material_id as string || undefined,
        subItemId: row.sub_item_id as string || undefined,
        quantity: row.quantity as number
      });
    });
    return Object.values(grouped);
  },
  saveRecipe: async (recipe: Recipe) => {
    const queries = [
      { sql: "DELETE FROM recipes WHERE item_id = ? AND restaurant_id = ?", args: [recipe.itemId, recipe.restaurantId] },
      ...recipe.ingredients.map(ing => ({
        sql: "INSERT INTO recipes (item_id, material_id, sub_item_id, quantity, restaurant_id) VALUES (?, ?, ?, ?, ?)",
        args: [
          recipe.itemId, 
          ing.materialId || null, 
          ing.subItemId || null, 
          ing.quantity, 
          recipe.restaurantId
        ]
      }))
    ];
    await client.batch(queries, "write");
  },
  deleteRecipe: async (itemId: string, restaurantId: string) => {
    await client.execute({
      sql: "DELETE FROM recipes WHERE item_id = ? AND restaurant_id = ?",
      args: [itemId, restaurantId]
    });
  },

  // Sales
  getSales: async (restaurantId: string): Promise<SaleEntry[]> => {
    const rs = await client.execute({
      sql: "SELECT id, item_id as itemId, quantity_sold as quantitySold, sale_date as date, restaurant_id as restaurantId FROM sales WHERE restaurant_id = ? ORDER BY sale_date DESC",
      args: [restaurantId]
    });
    return rs.rows.map(row => ({
      id: row.id as string,
      itemId: row.itemId as string,
      quantitySold: row.quantitySold as number,
      date: row.date as string,
      restaurantId: row.restaurantId as string
    }));
  },
  saveSales: async (newSales: SaleEntry[]) => {
    const queries = newSales.map(s => ({
      sql: "INSERT INTO sales (id, item_id, quantity_sold, sale_date, restaurant_id) VALUES (?, ?, ?, ?, ?)",
      args: [s.id, s.itemId, s.quantitySold, s.date, s.restaurantId]
    }));
    await client.batch(queries, "write");
  },
  deleteSale: async (id: string) => {
    await client.execute({ sql: "DELETE FROM sales WHERE id = ?", args: [id] });
  },
  updateSale: async (id: string, quantity: number) => {
    await client.execute({
      sql: "UPDATE sales SET quantity_sold = ? WHERE id = ?",
      args: [quantity, id]
    });
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { ChefHat, Loader2, CheckCircle2, AlertCircle, X, Store, Settings, Plus, Trash2, ArrowRight, Copy, Lock, KeyRound } from 'lucide-react';
import { 
  Material, SalesItem, Recipe, SaleEntry,
  MaterialGroup, SalesItemGroup, Restaurant
} from './types';
import { db, initDb } from './db';

// Components
import Sidebar from './components/Sidebar';
import Header from './components/Header';
import MaterialsPage from './components/MaterialsPage';
import SalesItemsPage from './components/SalesItemsPage';
import RecipeBuilderPage from './components/RecipeBuilderPage';
import SalesEntryPage from './components/SalesEntryPage';
import ReportsPage from './components/ReportsPage';
import QuickQueryPage from './components/QuickQueryPage';

interface Toast {
  id: string;
  message: string;
  type: 'success' | 'error';
}

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [pin, setPin] = useState('');
  const [authError, setAuthError] = useState('');

  const [currentRestaurant, setCurrentRestaurant] = useState<Restaurant | null>(null);
  const [isManagerMode, setIsManagerMode] = useState(false);
  const [restaurants, setRestaurants] = useState<Restaurant[]>([]);
  const [newRestName, setNewRestName] = useState('');
  const [isCloning, setIsCloning] = useState<string | null>(null);

  const [activeTab, setActiveTab] = useState<'materials' | 'items' | 'recipes' | 'sales' | 'reports' | 'query'>('items');
  const [isLoading, setIsLoading] = useState(true);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [toasts, setToasts] = useState<Toast[]>([]);

  const [materials, setMaterials] = useState<Material[]>([]);
  const [materialGroups, setMaterialGroups] = useState<MaterialGroup[]>([]);
  const [salesItems, setSalesItems] = useState<SalesItem[]>([]);
  const [salesItemGroups, setSalesItemGroups] = useState<SalesItemGroup[]>([]);
  const [recipes, setRecipes] = useState<Recipe[]>([]);
  const [sales, setSales] = useState<SaleEntry[]>([]);

  const addToast = useCallback((message: string, type: 'success' | 'error' = 'success') => {
    const id = crypto.randomUUID();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => {
      setToasts(prev => prev.filter(t => t.id !== id));
    }, 3000);
  }, []);

  // Initial DB Load
  useEffect(() => {
    const init = async () => {
      await initDb();
      const rests = await db.getRestaurants();
      setRestaurants(rests);
      setIsLoading(false);
    };
    init();
  }, []);

  // Data load per Restaurant
  useEffect(() => {
    if (!currentRestaurant) return;

    const loadData = async () => {
      setIsLoading(true);
      try {
        const [mats, matGrps, items, itemGrps, recs, sls] = await Promise.all([
          db.getMaterials(currentRestaurant.id),
          db.getMaterialGroups(currentRestaurant.id),
          db.getItems(currentRestaurant.id),
          db.getSalesItemGroups(currentRestaurant.id),
          db.getRecipes(currentRestaurant.id),
          db.getSales(currentRestaurant.id)
        ]);
        setMaterials(mats);
        setMaterialGroups(matGrps);
        setSalesItems(items);
        setSalesItemGroups(itemGrps);
        setRecipes(recs);
        setSales(sls);
      } catch (error) {
        addToast("فشل تحميل بيانات المطعم", "error");
      } finally {
        setIsLoading(false);
      }
    };
    loadData();
  }, [currentRestaurant, addToast]);

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (pin === '147852') {
      setIsAuthenticated(true);
      setAuthError('');
    } else {
      setAuthError('رمز الدخول غير صحيح');
      setPin('');
    }
  };

  const handleCreateRestaurant = async () => {
    if (!newRestName.trim()) return;
    const r: Restaurant = { id: crypto.randomUUID(), name: newRestName.trim() };
    await db.saveRestaurant(r);
    setRestaurants(prev => [...prev, r]);
    setNewRestName('');
    addToast(`تم إنشاء مطعم "${r.name}" بنجاح`);
  };

  const handleCloneRestaurant = async (id: string, name: string) => {
    const newName = prompt(`أدخل اسم المطعم الجديد المستنسخ من "${name}":`, `${name} - نسخة`);
    if (!newName || !newName.trim()) return;

    setIsCloning(id);
    try {
      const cloned = await db.cloneRestaurant(id, newName.trim());
      setRestaurants(prev => [...prev, cloned]);
      addToast(`تم استنساخ "${name}" إلى "${cloned.name}" بنجاح`);
    } catch (err) {
      addToast("فشل استنساخ المطعم", "error");
    } finally {
      setIsCloning(null);
    }
  };

  const handleDeleteRestaurant = async (id: string) => {
    if (confirm("سيتم حذف كافة بيانات المطعم بشكل نهائي! هل أنت متأكد؟")) {
      await db.deleteRestaurant(id);
      setRestaurants(prev => prev.filter(r => r.id !== id));
      addToast("تم حذف المطعم وبياناته");
    }
  };

  const handleAddMaterialGroup = async (g: Omit<MaterialGroup, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const group = { ...g, restaurantId: currentRestaurant.id };
    await db.saveMaterialGroup(group);
    setMaterialGroups(prev => [...prev, group]);
  };
  const handleDeleteMaterialGroup = async (id: string) => {
    await db.deleteMaterialGroup(id);
    setMaterialGroups(prev => prev.filter(g => g.id !== id));
    setMaterials(prev => prev.map(m => m.groupId === id ? { ...m, groupId: undefined } : m));
  };

  const handleAddSalesItemGroup = async (g: Omit<SalesItemGroup, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const group = { ...g, restaurantId: currentRestaurant.id };
    await db.saveSalesItemGroup(group);
    setSalesItemGroups(prev => [...prev, group]);
  };
  const handleDeleteSalesItemGroup = async (id: string) => {
    await db.deleteSalesItemGroup(id);
    setSalesItemGroups(prev => prev.filter(g => g.id !== id));
    setSalesItems(prev => prev.map(i => i.groupId === id ? { ...i, groupId: undefined } : i));
  };

  const handleAddMaterial = async (m: Omit<Material, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const mat = { ...m, restaurantId: currentRestaurant.id };
    await db.saveMaterial(mat);
    setMaterials(prev => [...prev, mat]);
  };
  const handleUpdateMaterial = async (m: Omit<Material, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const mat: Material = { ...m, restaurantId: currentRestaurant.id };
    await db.saveMaterial(mat);
    setMaterials(prev => prev.map(old => old.id === m.id ? mat : old));
  };
  const handleDeleteMaterial = async (id: string) => {
    await db.deleteMaterial(id);
    setMaterials(prev => prev.filter(m => m.id !== id));
  };

  const handleAddItem = async (i: Omit<SalesItem, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const item = { ...i, restaurantId: currentRestaurant.id };
    await db.saveItem(item);
    setSalesItems(prev => [...prev, item]);
  };
  const handleUpdateItem = async (i: Omit<SalesItem, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const item: SalesItem = { ...i, restaurantId: currentRestaurant.id };
    await db.saveItem(item);
    setSalesItems(prev => prev.map(old => old.id === i.id ? item : old));
  };
  const handleDeleteItem = async (id: string) => {
    await db.deleteItem(id);
    setSalesItems(prev => prev.filter(i => i.id !== id));
  };

  const handleSaveRecipe = async (r: Omit<Recipe, 'restaurantId'>) => {
    if (!currentRestaurant) return;
    const recipe = { ...r, restaurantId: currentRestaurant.id };
    await db.saveRecipe(recipe);
    setRecipes(prev => {
      const exists = prev.some(old => old.itemId === recipe.itemId);
      return exists ? prev.map(old => old.itemId === recipe.itemId ? recipe : old) : [...prev, recipe];
    });
    addToast('تم حفظ الوصفة بنجاح');
  };

  const handleDeleteRecipe = async (itemId: string) => {
    if (!currentRestaurant) return;
    await db.deleteRecipe(itemId, currentRestaurant.id);
    setRecipes(prev => prev.filter(r => r.itemId !== itemId));
    addToast('تم حذف الوصفة بنجاح');
  };

  const handleSaveSales = async (entries: Omit<SaleEntry, 'restaurantId'>[]) => {
    if (!currentRestaurant) return;
    const salesWithId = entries.map(e => ({ ...e, restaurantId: currentRestaurant.id }));
    await db.saveSales(salesWithId);
    setSales(prev => [...salesWithId, ...prev]);
    addToast('تم تسجيل المبيعات بنجاح');
  };

  const handleDeleteSale = async (id: string) => {
    await db.deleteSale(id);
    setSales(prev => prev.filter(s => s.id !== id));
    addToast('تم حذف عملية البيع');
  };

  const handleUpdateSale = async (id: string, quantity: number) => {
    await db.updateSale(id, quantity);
    setSales(prev => prev.map(s => s.id === id ? { ...s, quantitySold: quantity } : s));
    addToast('تم تعديل الكمية بنجاح');
  };

  if (!isAuthenticated) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4" dir="rtl">
        <div className="bg-white p-8 rounded-3xl shadow-2xl w-full max-w-md text-center">
          <div className="mb-6 flex justify-center">
            <div className="bg-emerald-100 p-4 rounded-full">
              <Lock className="w-10 h-10 text-emerald-600" />
            </div>
          </div>
          <h1 className="text-2xl font-bold text-slate-800 mb-2">تسجيل الدخول للنظام</h1>
          <p className="text-slate-500 mb-8 text-sm">أدخل رمز الدخول للمتابعة</p>

          <form onSubmit={handleLogin} className="space-y-6">
            <div className="relative">
              <KeyRound className="absolute top-1/2 -translate-y-1/2 right-4 text-slate-400 w-5 h-5" />
              <input 
                type="password" 
                maxLength={6}
                placeholder="رمز الدخول (PIN)" 
                className="w-full bg-slate-50 border border-slate-200 rounded-xl px-12 py-3.5 text-lg font-bold text-center tracking-widest outline-none focus:ring-2 focus:ring-emerald-500 focus:border-transparent transition-all"
                value={pin}
                onChange={(e) => setPin(e.target.value)}
                autoFocus
              />
            </div>
            {authError && <p className="text-rose-500 text-sm font-bold animate-pulse">{authError}</p>}
            <button className="w-full bg-emerald-600 text-white py-3.5 rounded-xl font-bold hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-500/30">
              دخول
            </button>
          </form>
          <p className="mt-8 text-xs text-slate-400">CulinaTrack v1.2</p>
        </div>
      </div>
    );
  }

  if (isLoading && !currentRestaurant) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <Loader2 className="w-12 h-12 text-emerald-500 animate-spin" />
        <p className="mt-4 font-bold text-slate-600">جاري تهيئة النظام...</p>
      </div>
    );
  }

  // --- Restaurant Selection Screen ---
  if (!currentRestaurant) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4" dir="rtl">
        <div className="max-w-4xl w-full">
          <div className="text-center mb-10">
            <ChefHat className="w-16 h-16 text-emerald-500 mx-auto mb-4" />
            <h1 className="text-3xl font-bold text-slate-800">CulinaTrack</h1>
            <p className="text-slate-500 mt-2">نظام إدارة استهلاك المواد الخام للمطاعم</p>
          </div>

          {!isManagerMode ? (
            <div className="space-y-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {restaurants.map(r => (
                  <button
                    key={r.id}
                    onClick={() => setCurrentRestaurant(r)}
                    className="bg-white p-8 rounded-3xl shadow-sm border-2 border-transparent hover:border-emerald-500 hover:shadow-xl hover:-translate-y-1 transition-all group text-right"
                  >
                    <div className="bg-emerald-50 w-12 h-12 rounded-2xl flex items-center justify-center mb-4 group-hover:bg-emerald-500 transition-colors">
                      <Store className="w-6 h-6 text-emerald-500 group-hover:text-white" />
                    </div>
                    <h3 className="text-xl font-bold text-slate-800">{r.name}</h3>
                    <p className="text-slate-400 text-sm mt-1 flex items-center gap-1">دخول للنظام <ArrowRight className="w-3 h-3" /></p>
                  </button>
                ))}

                {restaurants.length === 0 && (
                  <div className="col-span-full py-20 text-center border-2 border-dashed rounded-3xl text-slate-400">
                    لا يوجد مطاعم مسجلة حالياً
                  </div>
                )}
              </div>
              <button 
                onClick={() => setIsManagerMode(true)}
                className="w-full flex items-center justify-center gap-2 py-4 bg-slate-100 hover:bg-slate-200 text-slate-600 rounded-2xl font-bold transition-colors"
              >
                <Settings className="w-5 h-5" /> لوحة تحكم المدير (إضافة واستنساخ مطاعم)
              </button>
            </div>
          ) : (
            <div className="bg-white p-8 rounded-3xl shadow-xl animate-in zoom-in duration-300">
              <div className="flex items-center justify-between mb-8">
                <h2 className="text-2xl font-bold text-slate-800">إدارة المطاعم</h2>
                <button onClick={() => setIsManagerMode(false)} className="text-slate-400 hover:text-slate-600"><X /></button>
              </div>

              <div className="space-y-6">
                <div className="flex gap-2">
                  <input 
                    type="text" 
                    placeholder="اسم المطعم الجديد" 
                    className="flex-1 border rounded-xl px-4 py-3 outline-none focus:ring-2 focus:ring-emerald-500"
                    value={newRestName}
                    onChange={(e) => setNewRestName(e.target.value)}
                  />
                  <button 
                    onClick={handleCreateRestaurant}
                    className="bg-emerald-500 text-white px-6 py-3 rounded-xl font-bold hover:bg-emerald-600"
                  >
                    إضافة مطعم
                  </button>
                </div>

                <div className="divide-y">
                  {restaurants.map(r => (
                    <div key={r.id} className="py-4 flex items-center justify-between group">
                      <div className="flex items-center gap-3">
                        <Store className="w-5 h-5 text-slate-400" />
                        <span className="font-bold text-slate-700">{r.name}</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <button 
                          onClick={() => handleCloneRestaurant(r.id, r.name)}
                          disabled={isCloning === r.id}
                          className="flex items-center gap-1 px-3 py-1.5 text-blue-500 hover:bg-blue-50 rounded-lg transition-colors text-sm font-bold disabled:opacity-50"
                          title="استنساخ المطعم"
                        >
                          {isCloning === r.id ? <Loader2 className="w-4 h-4 animate-spin" /> : <Copy className="w-4 h-4" />}
                          استنساخ
                        </button>
                        <button 
                          onClick={() => handleDeleteRestaurant(r.id)}
                          className="p-2 text-rose-400 hover:bg-rose-50 hover:text-rose-600 rounded-lg transition-colors"
                          title="حذف المطعم"
                        >
                          <Trash2 className="w-5 h-5" />
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    );
  }

  const renderContent = () => {
    switch (activeTab) {
      case 'materials':
        return (
          <MaterialsPage 
            materials={materials}
            groups={materialGroups} 
            onAdd={handleAddMaterial} 
            onUpdate={handleUpdateMaterial} 
            onDelete={handleDeleteMaterial}
            onAddGroup={handleAddMaterialGroup}
            onUpdateGroup={(g) => db.saveMaterialGroup({ ...g, restaurantId: currentRestaurant.id })}
            onDeleteGroup={handleDeleteMaterialGroup}
          />
        );
      case 'items':
        return (
          <SalesItemsPage 
            items={salesItems}
            groups={salesItemGroups}
            onAdd={handleAddItem} 
            onUpdate={handleUpdateItem} 
            onDelete={handleDeleteItem} 
            onAddGroup={handleAddSalesItemGroup}
            onUpdateGroup={(g) => db.saveSalesItemGroup({ ...g, restaurantId: currentRestaurant.id })}
            onDeleteGroup={handleDeleteSalesItemGroup}
          />
        );
      case 'recipes':
        return (
          <RecipeBuilderPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
            onSave={handleSaveRecipe}
            onDelete={handleDeleteRecipe}
          />
        );
      case 'sales':
        return (
          <SalesEntryPage 
            items={salesItems} 
            sales={sales} 
            onSave={handleSaveSales} 
            onDeleteSale={handleDeleteSale}
            onUpdateSale={handleUpdateSale}
          />
        );
      case 'reports':
        return (
          <ReportsPage 
            materials={materials} 
            items={salesItems} 
            recipes={recipes} 
            sales={sales} 
          />
        );
      case 'query':
        return (
          <QuickQueryPage 
            items={salesItems} 
            materials={materials} 
            recipes={recipes} 
          />
        );
      default:
        return null;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50 text-slate-900 overflow-x-hidden" dir="rtl">
      {isLoading && currentRestaurant && (
        <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[200] flex items-center justify-center">
          <Loader2 className="w-10 h-10 text-emerald-500 animate-spin" />
        </div>
      )}

      <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[300] flex flex-col gap-3 pointer-events-none">
        {toasts.map(toast => (
          <div 
            key={toast.id} 
            className={`flex items-center gap-3 px-6 py-4 rounded-2xl shadow-2xl border pointer-events-auto animate-in slide-in-from-top-4 duration-300 ${
              toast.type === 'success' ? 'bg-white border-emerald-100 text-emerald-900' : 'bg-rose-50 border-rose-100 text-rose-900'
            }`}
          >
            {toast.type === 'success' ? <CheckCircle2 className="w-5 h-5 text-emerald-500" /> : <AlertCircle className="w-5 h-5 text-rose-500" />}
            <span className="font-bold text-sm">{toast.message}</span>
            <button onClick={() => setToasts(prev => prev.filter(t => t.id !== toast.id))} className="mr-4 text-slate-400 hover:text-slate-600">
              <X className="w-4 h-4" />
            </button>
          </div>
        ))}
      </div>

      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={(tab: any) => setActiveTab(tab)} 
        isOpen={isSidebarOpen} 
        setIsOpen={setIsSidebarOpen} 
        restaurantName={currentRestaurant.name}
        onExit={() => setCurrentRestaurant(null)}
      />

      <div className="flex-1 flex flex-col min-w-0">
        <Header 
          activeTab={activeTab} 
          onOpenSidebar={() => setIsSidebarOpen(true)}
        />
        <main className="p-4 md:p-8 flex-1 overflow-y-auto">
          {renderContent()}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Calculator, Save, Package, UtensilsCrossed, ArrowRightLeft, Info, ChefHat, Printer, Edit3, ArrowRight, Search, FileText } from 'lucide-react';
import { SalesItem, Material, Recipe, RecipeIngredient } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
  onSave: (recipe: Omit<Recipe, 'restaurantId'>) => Promise<void>;
  onDelete?: (itemId: string) => Promise<void>;
}

interface LocalRecipeIngredient extends Omit<RecipeIngredient, 'quantity'> {
  quantity: string | number;
}

const RecipeBuilderPage: React.FC<Props> = ({ items, materials, recipes, onSave, onDelete }) => {
  const [view, setView] = useState<'list' | 'edit'>('list');
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [localIngredients, setLocalIngredients] = useState<LocalRecipeIngredient[]>([]);
  const [isSaving, setIsSaving] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');

  // When selectedItemId changes (in edit mode), load existing recipe or reset
  useEffect(() => {
    if (view === 'edit' && selectedItemId) {
      const existing = recipes.find(r => r.itemId === selectedItemId);
      setLocalIngredients(existing ? existing.ingredients.map(i => ({...i})) : []);
    }
  }, [selectedItemId, recipes, view]);

  const getSubItemRecipe = (subItemId: string) => {
    const recipe = recipes.find(r => r.itemId === subItemId);
    if (!recipe) return null;
    return recipe.ingredients.map(ing => {
      const name = ing.materialId 
        ? materials.find(m => m.id === ing.materialId)?.name 
        : items.find(i => i.id === ing.subItemId)?.name;
      return { name, quantity: ing.quantity };
    });
  };

  const addIngredient = (type: 'material' | 'item') => {
    if (type === 'material') {
      if (materials.length === 0) return;
      setLocalIngredients([...localIngredients, { materialId: materials[0].id, quantity: '' }]);
    } else {
      if (items.length === 0) return;
      // Filter out the selected item itself to prevent circular reference
      const otherItems = items.filter(i => i.id !== selectedItemId);
      if (otherItems.length === 0) return;
      setLocalIngredients([...localIngredients, { subItemId: otherItems[0].id, quantity: '' }]);
    }
  };

  const updateIngredient = (idx: number, field: keyof LocalRecipeIngredient, value: any) => {
    const next = [...localIngredients];
    // @ts-ignore - dynamic assignment
    next[idx] = { ...next[idx], [field]: value };

    // Ensure if we update materialId, subItemId is cleared and vice versa
    if (field === 'materialId') delete next[idx].subItemId;
    if (field === 'subItemId') delete next[idx].materialId;

    setLocalIngredients(next);
  };

  const toggleType = (idx: number) => {
    const current = localIngredients[idx];
    const next = [...localIngredients];
    if (current.materialId) {
      const otherItems = items.filter(i => i.id !== selectedItemId);
      next[idx] = { subItemId: otherItems[0]?.id || '', quantity: current.quantity };
    } else {
      next[idx] = { materialId: materials[0]?.id || '', quantity: current.quantity };
    }
    setLocalIngredients(next);
  };

  const removeIngredient = (idx: number) => {
    setLocalIngredients(localIngredients.filter((_, i) => i !== idx));
  };

  const handleSave = async () => {
    if (!selectedItemId) return;
    setIsSaving(true);

    const ingredientsToSave: RecipeIngredient[] = localIngredients.map(ing => ({
      materialId: ing.materialId,
      subItemId: ing.subItemId,
      quantity: typeof ing.quantity === 'string' ? parseFloat(ing.quantity) || 0 : ing.quantity
    }));

    await onSave({ itemId: selectedItemId, ingredients: ingredientsToSave });
    setIsSaving(false);
    setView('list');
    setSelectedItemId('');
  };

  const handleDelete = async (id: string) => {
    if (confirm('هل أنت متأكد من حذف هذه الوصفة بالكامل؟')) {
      if (onDelete) await onDelete(id);
    }
  };

  const selectedItemName = items.find(i => i.id === selectedItemId)?.name;

  // Render List View
  if (view === 'list') {
    const recipesList = recipes.map(r => {
      const item = items.find(i => i.id === r.itemId);
      return { ...r, itemName: item?.name || 'صنف محذوف', itemUnit: item?.unit || '-' };
    }).filter(r => r.itemName.toLowerCase().includes(searchTerm.toLowerCase()));

    return (
      <div className="max-w-6xl mx-auto space-y-6">
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-2">
            <div className="bg-emerald-100 dark:bg-emerald-900/30 p-2 rounded-lg">
               <ChefHat className="w-6 h-6 text-emerald-600 dark:text-emerald-400" />
            </div>
            <div>
               <h2 className="text-xl font-bold text-slate-800 dark:text-white">سجل الوصفات الفنية</h2>
               <p className="text-sm text-slate-500">إدارة مكونات ومقادير الأصناف</p>
            </div>
          </div>
          <button 
            onClick={() => { setSelectedItemId(''); setLocalIngredients([]); setView('edit'); }}
            className="flex items-center gap-2 bg-emerald-600 text-white px-5 py-2.5 rounded-xl font-bold hover:bg-emerald-700 shadow-lg shadow-emerald-500/20 transition-all active:scale-95"
          >
            <Plus className="w-5 h-5" /> إنشاء وصفة جديدة
          </button>
        </div>

        <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden">
          <div className="p-4 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 flex gap-4">
            <div className="relative flex-1 max-w-md">
              <Search className="absolute top-1/2 -translate-y-1/2 right-3 w-4 h-4 text-slate-400" />
              <input 
                type="text" 
                placeholder="بحث عن وصفة..." 
                className="w-full pl-4 pr-10 py-2 rounded-xl border border-slate-200 dark:border-slate-700 dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full text-right">
              <thead className="bg-slate-50 dark:bg-slate-800 text-slate-500 font-bold text-xs uppercase">
                <tr>
                  <th className="px-6 py-4">اسم الصنف</th>
                  <th className="px-6 py-4">عدد المكونات</th>
                  <th className="px-6 py-4">وحدة القياس</th>
                  <th className="px-6 py-4 text-left">الإجراءات</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                {recipesList.length > 0 ? (
                  recipesList.map(recipe => (
                    <tr key={recipe.itemId} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors">
                      <td className="px-6 py-4 font-bold text-slate-800 dark:text-slate-200">{recipe.itemName}</td>
                      <td className="px-6 py-4">
                        <span className="bg-blue-50 text-blue-600 px-2 py-1 rounded-lg text-xs font-bold">
                          {recipe.ingredients.length} مكونات
                        </span>
                      </td>
                      <td className="px-6 py-4 text-slate-500">{recipe.itemUnit}</td>
                      <td className="px-6 py-4">
                        <div className="flex justify-end gap-2">
                          <button 
                            onClick={() => { setSelectedItemId(recipe.itemId); setView('edit'); }}
                            className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg transition-colors"
                            title="تعديل الوصفة"
                          >
                            <Edit3 className="w-4 h-4" />
                          </button>
                          <button 
                            onClick={() => handleDelete(recipe.itemId)}
                            className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg transition-colors"
                            title="حذف الوصفة"
                          >
                            <Trash2 className="w-4 h-4" />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))
                ) : (
                  <tr>
                    <td colSpan={4} className="px-6 py-12 text-center text-slate-400">
                      <div className="flex flex-col items-center gap-2">
                        <FileText className="w-8 h-8 opacity-20" />
                        <p>لا توجد وصفات مسجلة تطابق بحثك</p>
                      </div>
                    </td>
                  </tr>
                )}
              </tbody>
            </table>
          </div>
        </div>
      </div>
    );
  }

  // Render Edit/Create View
  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="flex items-center gap-2 text-sm text-slate-500 mb-4 print:hidden">
        <button onClick={() => setView('list')} className="hover:text-emerald-600 flex items-center gap-1 transition-colors">
          <ArrowRight className="w-4 h-4" /> العودة للقائمة
        </button>
        <span>/</span>
        <span className="font-bold text-slate-800 dark:text-white">تعديل الوصفة</span>
      </div>

      <div className="print:hidden space-y-6">
        {!selectedItemId && (
           <div className="bg-white dark:bg-slate-900 p-8 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 text-center">
             <h3 className="text-lg font-bold text-slate-800 dark:text-white mb-4">اختيار الصنف لإنشاء الوصفة</h3>
             <div className="max-w-md mx-auto">
               <select
                className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 font-medium transition-colors"
                value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}
              >
                <option value="">-- اختر صنفاً من القائمة --</option>
                {items.filter(i => !recipes.some(r => r.itemId === i.id)).map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
              </select>
              <p className="text-xs text-slate-400 mt-2">تظهر هنا فقط الأصناف التي ليس لها وصفة مسجلة بعد.</p>
             </div>
           </div>
        )}

        {selectedItemId && (
          <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden animate-in fade-in slide-in-from-bottom-2 transition-colors">
            <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex flex-col md:flex-row justify-between items-center bg-slate-50/50 dark:bg-slate-800/50 gap-4">
              <div>
                 <h3 className="font-bold text-slate-800 dark:text-white flex items-center gap-2 text-lg">
                  <UtensilsCrossed className="w-5 h-5 text-emerald-500" />
                  {selectedItemName}
                </h3>
                <p className="text-xs text-slate-500 mt-1">قم بإضافة المكونات والمقادير لهذا الصنف</p>
              </div>
              <div className="flex flex-wrap gap-2">
                 <button onClick={() => addIngredient('material')} className="flex items-center gap-2 text-xs bg-slate-800 dark:bg-slate-700 text-white px-4 py-2 rounded-xl font-bold hover:bg-slate-700 transition-colors"><Package className="w-3.5 h-3.5" /> إضافة خامة</button>
                 <button onClick={() => addIngredient('item')} className="flex items-center gap-2 text-xs bg-blue-600 text-white px-4 py-2 rounded-xl font-bold hover:bg-blue-700 transition-colors"><ChefHat className="w-3.5 h-3.5" /> إضافة صنف مجهز</button>
                 <button onClick={() => window.print()} className="flex items-center gap-2 text-xs bg-slate-100 text-slate-700 border border-slate-300 px-4 py-2 rounded-xl font-bold hover:bg-slate-200 transition-colors"><Printer className="w-3.5 h-3.5" /> طباعة</button>
                 <button onClick={handleSave} disabled={isSaving} className="flex items-center gap-2 text-sm bg-emerald-500 text-white px-6 py-2 rounded-xl font-bold shadow-lg shadow-emerald-500/20 disabled:bg-slate-300 transition-all hover:scale-105 active:scale-95"><Save className="w-4 h-4" /> {isSaving ? 'جاري الحفظ...' : 'حفظ الوصفة'}</button>
              </div>
            </div>
            <div className="p-6 space-y-3">
              {localIngredients.length === 0 ? (
                <div className="text-center py-16 text-slate-400 dark:text-slate-600 border-2 border-dashed border-slate-100 dark:border-slate-800 rounded-2xl">
                  <Calculator className="w-12 h-12 mx-auto mb-3 opacity-20" />
                  <p>لا توجد مكونات مضافة بعد.</p>
                </div>
              ) : (
                localIngredients.map((ing, idx) => {
                  const isSubItem = !!ing.subItemId;
                  const material = materials.find(m => m.id === ing.materialId);
                  const item = items.find(i => i.id === ing.subItemId);
                  const unit = isSubItem ? (item?.unit || 'وحدة') : material?.unit;
                  const subRecipe = isSubItem ? getSubItemRecipe(ing.subItemId!) : null;

                  return (
                    <div key={idx} className={`flex flex-col md:flex-row gap-4 items-start p-4 rounded-xl border transition-all group ${
                      isSubItem 
                        ? 'bg-blue-50/40 border-blue-200 dark:bg-blue-900/10 dark:border-blue-800/40' 
                        : 'bg-white border-slate-200 dark:bg-slate-800/30 dark:border-slate-700 hover:border-emerald-200'
                    }`}>
                      <div className="flex-1 w-full">
                        <div className="flex items-center justify-between mb-1 mr-1">
                          <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider flex items-center gap-1.5">
                            {isSubItem ? (
                              <span className="flex items-center gap-1 text-blue-600 dark:text-blue-400">
                                <ChefHat className="w-3.5 h-3.5" /> صنف مجهز (وصفة فرعية)
                              </span>
                            ) : (
                              <span className="flex items-center gap-1">
                                <Package className="w-3.5 h-3.5 text-slate-500" /> خامة أساسية
                              </span>
                            )}
                          </label>
                          <button onClick={() => toggleType(idx)} className="text-[10px] text-emerald-500 hover:underline flex items-center gap-1 font-bold opacity-0 group-hover:opacity-100 transition-opacity">
                            <ArrowRightLeft className="w-3 h-3" /> تبديل النوع
                          </button>
                        </div>
                        <div className="flex gap-2 items-center">
                          <select 
                            className={`w-full border rounded-xl px-4 py-2.5 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-emerald-500 transition-colors ${
                              isSubItem ? 'border-blue-200 dark:border-blue-800 font-bold' : 'border-slate-200 dark:border-slate-700'
                            }`} 
                            value={isSubItem ? ing.subItemId : ing.materialId} 
                            onChange={(e) => updateIngredient(idx, isSubItem ? 'subItemId' : 'materialId', e.target.value)}
                          >
                            {isSubItem ? (
                              items.filter(i => i.id !== selectedItemId).map(i => <option key={i.id} value={i.id}>{i.name}</option>)
                            ) : (
                              materials.map(m => <option key={m.id} value={m.id}>{m.name} ({m.unit})</option>)
                            )}
                          </select>

                          {isSubItem && (
                            <div className="relative group/tooltip">
                              <div className="p-2 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg cursor-help hover:bg-blue-200 transition-colors">
                                <Info className="w-4 h-4" />
                              </div>
                              <div className="invisible group-hover/tooltip:visible absolute z-50 bottom-full left-1/2 -translate-x-1/2 mb-2 w-56 bg-slate-800 text-white p-3 rounded-xl shadow-2xl border border-slate-700 pointer-events-none">
                                <p className="font-bold border-b border-slate-700 pb-1.5 mb-2 text-[10px] text-blue-300">مكونات الصنف المختار:</p>
                                {subRecipe && subRecipe.length > 0 ? (
                                  <ul className="space-y-1">
                                    {subRecipe.map((r, i) => (
                                      <li key={i} className="flex justify-between items-center text-[9px] text-slate-300">
                                        <span>{r.name}</span>
                                        <span className="font-mono text-blue-200">{r.quantity}</span>
                                      </li>
                                    ))}
                                  </ul>
                                ) : (
                                  <p className="text-[9px] italic text-rose-400">لا توجد وصفة مسجلة لهذا الصنف</p>
                                )}
                              </div>
                            </div>
                          )}
                        </div>
                      </div>
                      <div className="w-full md:w-48">
                        <label className="block text-[10px] font-bold text-slate-400 dark:text-slate-500 mb-1 mr-1">الكمية لكل {unit}</label>
                        <input 
                          type="number" step="any"
                          className={`w-full border rounded-xl px-4 py-2.5 outline-none focus:ring-2 focus:ring-emerald-500 bg-white dark:bg-slate-800 dark:text-white font-mono font-bold transition-colors ${
                            isSubItem ? 'border-blue-200 dark:border-blue-800' : 'border-slate-200 dark:border-slate-700'
                          }`} 
                          value={ing.quantity} 
                          onChange={(e) => updateIngredient(idx, 'quantity', e.target.value)} 
                          placeholder="0.00"
                        />
                      </div>
                      <button onClick={() => removeIngredient(idx)} className="p-2.5 text-rose-500 hover:bg-rose-50 dark:hover:bg-rose-900/20 rounded-xl md:mt-5 self-end transition-colors"><Trash2 className="w-5 h-5" /></button>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        )}
      </div>

      {/* Printable View */}
      {selectedItemId && (
        <div className="hidden print:block bg-white p-8">
          <div className="text-center mb-8 border-b-2 border-slate-800 pb-4">
            <h1 className="text-3xl font-bold mb-2">بطاقة وصفة فنية</h1>
            <h2 className="text-xl text-slate-600">الصنف: {selectedItemName}</h2>
          </div>

          <table className="w-full text-right border-collapse">
            <thead>
              <tr className="border-b border-slate-300">
                <th className="py-2 text-sm font-bold text-slate-500">النوع</th>
                <th className="py-2 text-sm font-bold text-slate-500">المكون</th>
                <th className="py-2 text-sm font-bold text-slate-500">الكمية</th>
                <th className="py-2 text-sm font-bold text-slate-500">الوحدة</th>
              </tr>
            </thead>
            <tbody>
              {localIngredients.length > 0 ? (
                localIngredients.map((ing, idx) => {
                  const isSubItem = !!ing.subItemId;
                  const material = materials.find(m => m.id === ing.materialId);
                  const item = items.find(i => i.id === ing.subItemId);
                  const name = isSubItem ? item?.name : material?.name;
                  const unit = isSubItem ? (item?.unit || 'وحدة') : material?.unit;

                  return (
                    <tr key={idx} className="border-b border-slate-100">
                      <td className="py-3 text-sm">
                         {isSubItem ? <span className="font-bold">صنف مجهز</span> : <span>خامة أولية</span>}
                      </td>
                      <td className="py-3 font-bold">{name}</td>
                      <td className="py-3 font-mono text-lg">{ing.quantity}</td>
                      <td className="py-3 text-sm text-slate-500">{unit}</td>
                    </tr>
                  );
                })
              ) : (
                 <tr><td colSpan={4} className="py-6 text-center text-slate-400">لا توجد مكونات مسجلة</td></tr>
              )}
            </tbody>
          </table>

          <div className="mt-12 pt-4 border-t border-slate-200 flex justify-between text-xs text-slate-400">
             <span>تمت الطباعة من نظام CulinaTrack</span>
             <span>{new Date().toLocaleDateString('ar-EG')}</span>
          </div>
        </div>
      )}
    </div>
  );
};

