                    const i = items.find(x => x.id === item.itemId);
                    return (
                      <tr key={item.id} className="border-b border-slate-200">
                        <td className="py-2 font-bold">{i?.name}</td>
                        <td className="py-2 text-center">{item.quantitySold}</td>
