      </div>

      <div className="space-y-6">
        {[...groups, { id: 'ungrouped', name: 'أصناف غير مصنفة' }].map(group => {
          const groupItems = group.id === 'ungrouped' ? ungroupedItems : groupedItems[group.id] || [];
          if (groupItems.length === 0) return null;

          return (
            <div key={group.id} className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
              <div className="bg-slate-50 dark:bg-slate-800/50 px-6 py-3 border-b border-slate-100 dark:border-slate-800">
                <h4 className="font-bold text-slate-600 dark:text-slate-400 text-sm flex items-center gap-2">
                  <Tags className="w-3.5 h-3.5" /> {group.name}
                </h4>
              </div>
              <div className="overflow-x-auto">
                <table className="w-full text-right">
                  <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                    {groupItems.map((item) => (
                      <tr key={item.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-800/20 transition-colors">
                        {editingId === item.id ? (
                          <>
                            <td className="px-6 py-3">
                              <input type="text" className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-3 py-1 outline-none focus:ring-2 focus:ring-emerald-500" value={editName} onChange={(e) => setEditName(e.target.value)} autoFocus />
                            </td>
                            <td className="px-6 py-3 w-32">
                              <input type="text" className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-2 py-1 outline-none" value={editUnit} onChange={(e) => setEditUnit(e.target.value)} placeholder="الوحدة" />
                            </td>
                            <td className="px-6 py-3 w-32">
                              <input type="number" step="0.01" className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-2 py-1 outline-none" value={editPrice} onChange={(e) => setEditPrice(e.target.value)} />
                            </td>
                            <td className="px-6 py-3 w-40">
                              <select className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-lg px-2 py-1 outline-none" value={editGroupId} onChange={(e) => setEditGroupId(e.target.value)}>
                                <option value="">بدون مجموعة</option>
                                {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                              </select>
                            </td>
                            <td className="px-6 py-3 flex justify-end gap-2">
                              <button onClick={() => saveEdit(item.id)} className="p-1.5 text-emerald-600 hover:bg-emerald-50 rounded-lg"><Save className="w-4 h-4" /></button>
                              <button onClick={() => setEditingId(null)} className="p-1.5 text-slate-400 hover:bg-slate-100 rounded-lg"><X className="w-4 h-4" /></button>
                            </td>
                          </>
                        ) : (
                          <>
                            <td className="px-6 py-4 flex items-center gap-3">
                              <Utensils className="w-4 h-4 text-slate-300" />
                              <span className="font-bold text-slate-700 dark:text-slate-200">{item.name}</span>
                            </td>
                            <td className="px-6 py-4 text-slate-500 dark:text-slate-400 w-32 font-medium">
                              {item.unit || '-'}
                            </td>
                            <td className="px-6 py-4 text-blue-600 dark:text-blue-400 w-32 font-bold flex items-center gap-1">
                               {item.price ? item.price.toLocaleString() : '-'} <span className="text-[10px] opacity-60">ر.س</span>
                            </td>
                            <td className="px-6 py-4 w-40">
                              {/* Empty for symmetry */}
                            </td>
                            <td className="px-6 py-4 flex justify-end gap-1">
                              <button onClick={() => { setEditingId(item.id); setEditName(item.name); setEditUnit(item.unit || ''); setEditPrice(item.price?.toString() || ''); setEditGroupId(item.groupId || ''); }} className="p-2 text-blue-500 hover:bg-blue-50 rounded-lg" title="تعديل"><Edit3 className="w-4 h-4" /></button>
                              <button onClick={() => handleDelete(item.id, item.name)} className="p-2 text-rose-500 hover:bg-rose-50 rounded-lg" title="حذف"><Trash2 className="w-4 h-4" /></button>
                            </td>
                          </>
                        )}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          );
        })}

        {items.length === 0 && (
          <div className="bg-slate-100/50 dark:bg-slate-800/30 border-2 border-dashed border-slate-200 dark:border-slate-800 p-20 rounded-2xl flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4">
            <Utensils className="w-16 h-16 opacity-10" />
            <p className="font-medium">قائمة الأصناف فارغة حالياً</p>
          </div>
        )}
      </div>
    </div>
  );
};

export default SalesItemsPage;

import React, { useState, useMemo, useCallback } from 'react';
import { Calculator, Package, ArrowLeftRight, Search, UtensilsCrossed, Info, ChefHat, Layers, TrendingUp, DollarSign } from 'lucide-react';
import { SalesItem, Material, Recipe } from '../types';

interface Props {
  items: SalesItem[];
  materials: Material[];
  recipes: Recipe[];
}

const QuickQueryPage: React.FC<Props> = ({ items, materials, recipes }) => {
  const [selectedItemId, setSelectedItemId] = useState<string>('');
  const [queryQuantity, setQueryQuantity] = useState<string | number>(1);

  // Get direct ingredients for the current item
  const getDirectIngredients = (itemId: string) => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe) return [];
    return recipe.ingredients;
  };

  // Resolve total raw materials (full recursion)
  const resolveFlattenedIngredients = useCallback((itemId: string, multiplier: number, memo: Record<string, number> = {}, visited: Set<string> = new Set()): Record<string, number> => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe || visited.has(itemId)) return memo;

    visited.add(itemId);
    recipe.ingredients.forEach(ing => {
      const totalQty = (ing.quantity || 0) * multiplier;
      if (ing.materialId) {
        memo[ing.materialId] = (memo[ing.materialId] || 0) + totalQty;
      } else if (ing.subItemId) {
        resolveFlattenedIngredients(ing.subItemId, totalQty, memo, visited);
      }
    });
    visited.delete(itemId);
    return memo;
  }, [recipes]);

  const selectedItem = useMemo(() => items.find(i => i.id === selectedItemId), [items, selectedItemId]);
  const itemRecipe = useMemo(() => recipes.find(r => r.itemId === selectedItemId), [recipes, selectedItemId]);

  const rawMaterialsResults = useMemo(() => {
    if (!selectedItemId) return [];
    const qty = typeof queryQuantity === 'string' ? parseFloat(queryQuantity) || 0 : queryQuantity;
    const flattened = resolveFlattenedIngredients(selectedItemId, qty);

    return Object.entries(flattened).map(([matId, totalQty]) => {
      const mat = materials.find(m => m.id === matId);
      const qtyNum = Number(totalQty);
      const cost = (mat?.price || 0) * qtyNum;
      return { materialName: mat?.name || 'خامة مجهولة', unit: mat?.unit || '', total: qtyNum, cost, unitPrice: mat?.price || 0 };
    });
  }, [selectedItemId, queryQuantity, materials, resolveFlattenedIngredients]);

  const economicAnalysis = useMemo(() => {
     const totalCost = rawMaterialsResults.reduce((sum, r) => sum + r.cost, 0);
     const qty = typeof queryQuantity === 'string' ? parseFloat(queryQuantity) || 0 : queryQuantity;
     const sellingPrice = (selectedItem?.price || 0) * qty;
     const profit = sellingPrice - totalCost;
     const profitMargin = sellingPrice > 0 ? (profit / sellingPrice) * 100 : 0;

     return { totalCost, sellingPrice, profit, profitMargin };
  }, [rawMaterialsResults, selectedItem, queryQuantity]);

  const directSubItems = useMemo(() => {
    if (!selectedItemId) return [];
    const qty = typeof queryQuantity === 'string' ? parseFloat(queryQuantity) || 0 : queryQuantity;
    const directIngs = getDirectIngredients(selectedItemId);

    return directIngs
      .filter(ing => !!ing.subItemId)
      .map(ing => {
        const item = items.find(i => i.id === ing.subItemId);
        return { name: item?.name, qty: ing.quantity * qty, unit: item?.unit || 'وحدة' };
      });
  }, [selectedItemId, queryQuantity, items]);

  return (
    <div className="max-w-4xl mx-auto space-y-6">
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 transition-colors">
        <div className="flex items-center gap-3 mb-6">
          <div className="bg-blue-600 p-2 rounded-lg"><Calculator className="w-6 h-6 text-white" /></div>
          <div>
            <h3 className="text-lg font-bold text-slate-800 dark:text-white">الاستعلام الذكي وتحليل التكلفة</h3>
            <p className="text-sm text-slate-500 dark:text-slate-400">تحليل المكونات وحساب التكلفة التقديرية للإنتاج</p>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الصنف المستهدف</label>
            <select
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-medium transition-colors"
              value={selectedItemId}
              onChange={(e) => setSelectedItemId(e.target.value)}
            >
              <option value="">-- اختر صنفاً للاستعلام --</option>
              {items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-slate-700 dark:text-slate-300 mr-1">الكمية المقدرة</label>
            <input
              type="number" min="0.001" step="any"
              className="w-full border border-slate-200 dark:border-slate-700 rounded-xl px-4 py-3 bg-white dark:bg-slate-800 dark:text-white outline-none focus:ring-2 focus:ring-blue-500 font-mono font-bold transition-colors"
              value={queryQuantity}
              onChange={(e) => setQueryQuantity(e.target.value)}
            />
          </div>
        </div>
      </div>

      {selectedItemId ? (
        itemRecipe ? (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4 duration-500">

            {/* Economic Analysis Card */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <div className="flex items-center gap-2 text-slate-500 mb-2">
                  <Package className="w-4 h-4" /> <span className="text-xs font-bold">إجمالي تكلفة الخامات</span>
                </div>
                <div className="text-2xl font-bold text-slate-800 dark:text-white font-mono">
                  {economicAnalysis.totalCost.toLocaleString(undefined, { maximumFractionDigits: 2 })} <span className="text-xs opacity-50">ر.س</span>
                </div>
              </div>

              <div className="bg-white dark:bg-slate-900 p-5 rounded-2xl border border-slate-200 dark:border-slate-800 shadow-sm flex flex-col justify-between">
                <div className="flex items-center gap-2 text-blue-500 mb-2">
                  <DollarSign className="w-4 h-4" /> <span className="text-xs font-bold">سعر البيع المتوقع</span>
                </div>
                <div className="text-2xl font-bold text-blue-600 dark:text-blue-400 font-mono">
                  {economicAnalysis.sellingPrice > 0 ? economicAnalysis.sellingPrice.toLocaleString(undefined, { maximumFractionDigits: 2 }) : '-'} <span className="text-xs opacity-50">ر.س</span>
                </div>
              </div>

              <div className={`p-5 rounded-2xl border shadow-sm flex flex-col justify-between ${economicAnalysis.profit >= 0 ? 'bg-emerald-50 border-emerald-100 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-rose-50 border-rose-100 dark:bg-rose-900/10 dark:border-rose-800'}`}>
                <div className={`flex items-center gap-2 mb-2 ${economicAnalysis.profit >= 0 ? 'text-emerald-600' : 'text-rose-600'}`}>
                  <TrendingUp className="w-4 h-4" /> <span className="text-xs font-bold">الربح التقديري (الهامش)</span>
                </div>
                <div className={`text-2xl font-bold font-mono ${economicAnalysis.profit >= 0 ? 'text-emerald-700 dark:text-emerald-400' : 'text-rose-700 dark:text-rose-400'}`}>
                  {economicAnalysis.sellingPrice > 0 ? (
                    <>
                       {economicAnalysis.profit.toLocaleString(undefined, { maximumFractionDigits: 2 })} <span className="text-xs opacity-70">({economicAnalysis.profitMargin.toFixed(1)}%)</span>
                    </>
                  ) : (
                    <span className="text-sm">يرجى تحديد سعر البيع</span>
                  )}
                </div>
              </div>
            </div>

            {/* Direct Sub-Items Section */}
            {directSubItems.length > 0 && (
              <div className="bg-blue-50/50 dark:bg-blue-900/10 rounded-2xl border border-blue-100 dark:border-blue-800/50 overflow-hidden">
                <div className="p-4 bg-blue-100/50 dark:bg-blue-900/20 border-b border-blue-100 dark:border-blue-800/50 flex items-center gap-2">
                  <ChefHat className="w-5 h-5 text-blue-600 dark:text-blue-400" />
                  <h4 className="font-bold text-blue-800 dark:text-blue-300">الأصناف المجهزة الداخلة في التكوين</h4>
                </div>
                <div className="p-4 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                  {directSubItems.map((sub, i) => (
                    <div key={i} className="bg-white dark:bg-slate-800 p-3 rounded-xl border border-blue-50 dark:border-slate-700 flex justify-between items-center shadow-sm">
                      <span className="text-sm font-bold text-slate-700 dark:text-slate-300">{sub.name}</span>
                      <span className="font-mono text-blue-600 dark:text-blue-400 font-bold bg-blue-50 dark:bg-blue-900/40 px-2 py-1 rounded-lg text-xs">{sub.qty} {sub.unit}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {/* Total Raw Materials Section */}
            <div className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
              <div className="p-5 border-b border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-800/50 flex justify-between items-center">
                <div className="flex items-center gap-3">
                   <div className="bg-emerald-100 dark:bg-emerald-900/30 p-2 rounded-lg">
                     <Layers className="w-5 h-5 text-emerald-600 dark:text-emerald-400" />
                   </div>
                   <div>
                     <h4 className="font-bold text-slate-800 dark:text-white text-base">تحليل الخامات النهائية والتكلفة</h4>
                     <p className="text-[10px] text-slate-500 dark:text-slate-400">تفصيل الكميات وتكلفة كل خامة بناءً على متوسط سعر الشراء</p>
                   </div>
                </div>
              </div>

              <div className="overflow-x-auto">
                <table className="w-full text-right">
                  <thead className="bg-slate-50/50 dark:bg-slate-800/20 text-slate-500 dark:text-slate-400 text-xs font-bold uppercase border-b border-slate-100 dark:border-slate-800">
                    <tr>
                      <th className="px-6 py-4">اسم المادة الخام</th>
                      <th className="px-6 py-4 text-center">الكمية الصافية</th>
                      <th className="px-6 py-4 text-center">سعر الوحدة</th>
                      <th className="px-6 py-4 text-left">التكلفة الإجمالية</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
                    {rawMaterialsResults.map((res, idx) => (
                      <tr key={idx} className="hover:bg-slate-50 dark:hover:bg-slate-800/50 transition-colors group">
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <Package className="w-4 h-4 text-slate-300 group-hover:text-emerald-500 transition-colors" />
                            <span className="font-bold text-slate-700 dark:text-slate-200">{res.materialName}</span>
                          </div>
                        </td>
                        <td className="px-6 py-4 text-center">
                          <span className="font-mono font-bold text-slate-700 dark:text-slate-300 text-sm">
                            {res.total.toLocaleString(undefined, { minimumFractionDigits: 3 })}
                          </span>
                          <span className="mr-1.5 text-[10px] text-slate-400 font-bold">{res.unit}</span>
                        </td>
                        <td className="px-6 py-4 text-center text-sm font-mono text-slate-500">
                           {res.unitPrice > 0 ? res.unitPrice.toFixed(2) : '-'}
                        </td>
                        <td className="px-6 py-4 text-left">
                          <span className="font-mono font-bold text-emerald-600 dark:text-emerald-400 text-sm">
                            {res.cost.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                          </span>
                          <span className="mr-1 text-[10px] opacity-50">ر.س</span>
                        </td>
                      </tr>
                    ))}
                    <tr className="bg-slate-50 dark:bg-slate-800/50 font-bold border-t border-slate-200 dark:border-slate-700">
                      <td colSpan={3} className="px-6 py-4 text-slate-600 dark:text-slate-300">الإجمالي الكلي لتكلفة الخامات</td>
                      <td className="px-6 py-4 text-left font-mono text-lg text-emerald-700 dark:text-emerald-400">
                        {economicAnalysis.totalCost.toLocaleString(undefined, { minimumFractionDigits: 2 })} <span className="text-xs">ر.س</span>
                      </td>
                    </tr>
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        ) : (
          <div className="bg-rose-50 dark:bg-rose-900/10 border border-rose-100 dark:border-rose-900/30 p-12 rounded-3xl flex flex-col items-center gap-4 text-center">
            <UtensilsCrossed className="w-16 h-16 text-rose-500 opacity-50" />
            <div>
              <h4 className="font-bold text-rose-800 dark:text-rose-400 text-lg">لا توجد وصفة مسجلة</h4>
              <p className="text-sm text-rose-600 dark:text-rose-500 mt-1 max-w-sm">يرجى الذهاب إلى صفحة "إدارة الوصفات" لإعداد مكونات هذا الصنف أولاً ليتمكن النظام من تحليل الاستهلاك والتكاليف.</p>
            </div>
          </div>
        )
      ) : (
        <div className="bg-slate-100/50 dark:bg-slate-800/30 border-2 border-dashed border-slate-200 dark:border-slate-800 py-32 rounded-3xl flex flex-col items-center justify-center text-slate-400 dark:text-slate-600 gap-4">
          <div className="bg-white dark:bg-slate-800 p-6 rounded-full shadow-sm">
            <Search className="w-12 h-12 opacity-20" />
          </div>
          <p className="font-bold text-lg">اختر صنفاً مبيعات لبدء تحليل التكلفة والأرباح</p>
        </div>
      )}
    </div>
  );
};

export default QuickQueryPage;

import React, { useState, useMemo, useCallback, useRef, useEffect } from 'react';
import { Layers, List, FileSpreadsheet, Printer, ChefHat, Calendar, Filter, RotateCcw, Search, Package, Utensils, Info, HelpCircle, ChevronDown, CheckSquare, Square, Hash, X, Coins } from 'lucide-react';
import { Material, SalesItem, Recipe, SaleEntry, DetailedReportItem } from '../types';

interface Props {
  materials: Material[];
  items: SalesItem[];
  recipes: Recipe[];
  sales: SaleEntry[];
}

const ReportsPage: React.FC<Props> = ({ materials, items, recipes, sales }) => {
  const [reportType, setReportType] = useState<'aggregated' | 'detailed'>('aggregated');

  const today = new Date().toISOString().split('T')[0];
  const firstDayOfMonth = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString().split('T')[0];

  const [startDate, setStartDate] = useState<string>(firstDayOfMonth);
  const [endDate, setEndDate] = useState<string>(today);

  const [selectedMaterialId, setSelectedMaterialId] = useState<string>('');
  const [selectedItemId, setSelectedItemId] = useState<string>('');

  const [selectedRefNumbers, setSelectedRefNumbers] = useState<string[]>([]);
  const [isRefDropdownOpen, setIsRefDropdownOpen] = useState(false);
  const refDropdownRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    function handleClickOutside(event: MouseEvent) {
      if (refDropdownRef.current && !refDropdownRef.current.contains(event.target as Node)) {
        setIsRefDropdownOpen(false);
      }
    }
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const getFlattenedConsumption = useCallback((itemId: string, multiplier: number, memo: Record<string, number> = {}, visited: Set<string> = new Set()): Record<string, number> => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe || visited.has(itemId)) return memo;

    visited.add(itemId);
    recipe.ingredients.forEach(ing => {
      const qty = (ing.quantity || 0) * multiplier;
      if (ing.materialId) {
        memo[ing.materialId] = (memo[ing.materialId] || 0) + qty;
      } else if (ing.subItemId) {
        getFlattenedConsumption(ing.subItemId, qty, memo, visited);
      }
    });
    visited.delete(itemId);
    return memo;
  }, [recipes]);

  const getDirectRecipe = (itemId: string) => {
    const recipe = recipes.find(r => r.itemId === itemId);
    if (!recipe) return [];
    return recipe.ingredients.map(ing => ({
      name: ing.materialId ? materials.find(m => m.id === ing.materialId)?.name : items.find(i => i.id === ing.subItemId)?.name,
      isSub: !!ing.subItemId,
      qty: ing.quantity
    }));
  };

  const uniqueReferences = useMemo(() => {
    const refsMap = new Map<string, string>(); 
    sales.forEach(s => {
      if (s.referenceNumber && !refsMap.has(s.referenceNumber)) {
        refsMap.set(s.referenceNumber, s.date);
      }
    });
    return Array.from(refsMap.entries())
      .map(([ref, date]) => ({ ref, date }))
      .sort((a, b) => b.date.localeCompare(a.date));
  }, [sales]);

  const toggleRefSelection = (ref: string) => {
    setSelectedRefNumbers(prev => 
      prev.includes(ref) ? prev.filter(r => r !== ref) : [...prev, ref]
    );
  };

  const filteredSales = useMemo(() => {
    return sales.filter(sale => {
      const itemMatch = selectedItemId ? sale.itemId === selectedItemId : true;

      if (selectedRefNumbers.length > 0) {
        const refMatch = sale.referenceNumber && selectedRefNumbers.includes(sale.referenceNumber);
        return refMatch && itemMatch;
      }

      const saleDate = sale.date;
      const dateMatch = saleDate >= startDate && saleDate <= endDate;
      return dateMatch && itemMatch;
    });
  }, [sales, startDate, endDate, selectedItemId, selectedRefNumbers]);

  const aggregatedData = useMemo(() => {
    const consumptionMap: Record<string, number> = {};
    filteredSales.forEach(sale => {
      getFlattenedConsumption(sale.itemId, sale.quantitySold, consumptionMap);
    });

    const results = materials.map(m => ({
      name: m.name,
      unit: m.unit,
      total: consumptionMap[m.id] || 0,
      totalCost: (consumptionMap[m.id] || 0) * (m.price || 0),
      id: m.id
    }));

    return results.filter(item => {
      const matchesMaterial = selectedMaterialId ? item.id === selectedMaterialId : true;
      return matchesMaterial && (selectedMaterialId ? true : item.total > 0);
    });
  }, [materials, filteredSales, getFlattenedConsumption, selectedMaterialId]);

  const detailedData = useMemo(() => {
    const results: DetailedReportItem[] = [];
    const itemSalesMap: Record<string, number> = {};

    filteredSales.forEach(s => {
      itemSalesMap[s.itemId] = (itemSalesMap[s.itemId] || 0) + s.quantitySold;
    });

    Object.entries(itemSalesMap).forEach(([itemId, qtySold]) => {
      const item = items.find(i => i.id === itemId);
      if (item) {
        const revenue = (item.price || 0) * qtySold;
        const flatIngs = getFlattenedConsumption(itemId, 1); // Get unit consumption

        let totalCost = 0;
        const ingredients = Object.entries(flatIngs)
          .filter(([matId]) => !selectedMaterialId || matId === selectedMaterialId)
          .map(([matId, qtyPerUnit]) => {
            const mat = materials.find(m => m.id === matId);
            const totalQty = Number(qtyPerUnit) * Number(qtySold);
            const cost = totalQty * (mat?.price || 0);
            totalCost += cost;

            return {
              materialName: mat?.name || 'مجهول',
              unit: mat?.unit || '',
              consumedQuantity: totalQty,
              cost
            };
          });

        if (ingredients.length > 0) {
          results.push({ 
            itemName: item.name, 
            quantitySold: qtySold, 
            totalRevenue: revenue,
            totalCost,
            ingredients 
          });
        }
      }
    });
    return results;
  }, [items, filteredSales, materials, selectedMaterialId, getFlattenedConsumption]);

  const resetFilter = () => {
    setStartDate(firstDayOfMonth);
    setEndDate(today);
    setSelectedMaterialId('');
    setSelectedItemId('');
    setSelectedRefNumbers([]);
  };

  const exportCSV = () => {
    const BOM = "\uFEFF";
    let periodText = selectedRefNumbers.length > 0 
      ? `فواتير محددة (${selectedRefNumbers.length})` 
      : `${startDate} إلى ${endDate}`;

    let csvContent = `نظام CulinaTrack - تقرير استهلاك\nالفترة,${periodText}\n\n`;

    if (reportType === 'aggregated') {
      csvContent += "الخامة,الوحدة,الإجمالي,التكلفة\n";
      aggregatedData.forEach(r => csvContent += `"${r.name}","${r.unit}",${r.total.toFixed(3)},${r.totalCost.toFixed(2)}\n`);
      const totalCost = aggregatedData.reduce((acc, r) => acc + r.totalCost, 0);
      csvContent += `\n,,إجمالي التكلفة,${totalCost.toFixed(2)}\n`;
    } else {
      csvContent += "الصنف,المباع,الإيراد,التكلفة,الربح,الخامة,الكمية,الوحدة,تكلفة الخامة\n";
      detailedData.forEach(d => {
        d.ingredients.forEach(ing => {
          csvContent += `"${d.itemName}",${d.quantitySold},${d.totalRevenue},${d.totalCost},${d.totalRevenue - d.totalCost},"${ing.materialName}",${ing.consumedQuantity.toFixed(3)},"${ing.unit}",${ing.cost.toFixed(2)}\n`;
        });
      });
    }
    const blob = new Blob([BOM + csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.href = URL.createObjectURL(blob);
    link.download = `Report_${reportType}.csv`;
    link.click();
  };

  const grandTotalAggregatedCost = aggregatedData.reduce((sum, item) => sum + item.totalCost, 0);

  return (
    <div className="max-w-5xl mx-auto space-y-6">
      {/* Branding for Print */}
      <div className="hidden print:flex items-center justify-between mb-8 border-b-2 border-emerald-500 pb-4">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-500 p-2 rounded-lg"><ChefHat className="w-8 h-8 text-white" /></div>
          <div><h1 className="text-2xl font-bold">CulinaTrack</h1><p className="text-xs">نظام إدارة استهلاك المطاعم</p></div>
        </div>
        <div className="text-right">
          <h2 className="text-xl font-bold">تقرير {reportType === 'aggregated' ? 'استهلاك وتكاليف الخامات' : 'الربحية وتحليل المبيعات'}</h2>
          <p className="text-sm">
            {selectedRefNumbers.length > 0 ? `فواتير محددة: ${selectedRefNumbers.length}` : `الفترة: ${startDate} إلى ${endDate}`}
          </p>
        </div>
      </div>

      {/* Filter UI */}
      <div className="bg-white dark:bg-slate-900 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 no-print transition-colors">
        <div className="flex items-center gap-2 mb-6 text-slate-700 dark:text-slate-300 font-bold border-b border-slate-100 dark:border-slate-800 pb-4">
          <Filter className="w-5 h-5 text-emerald-500" /><h3>تصفية التقارير الذكية</h3>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 items-end">

          <div className="space-y-1.5 relative" ref={refDropdownRef}>
            <label className="text-xs font-bold text-slate-500 mr-1 flex items-center gap-1"><Hash className="w-3 h-3"/> أرقام الفواتير</label>
            <button 
              onClick={() => setIsRefDropdownOpen(!isRefDropdownOpen)}
              className={`w-full flex items-center justify-between border dark:border-slate-700 rounded-xl px-3 py-2 text-sm transition-all outline-none focus:ring-2 focus:ring-emerald-500 ${
                selectedRefNumbers.length > 0 
                  ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-900/20 dark:text-emerald-400' 
                  : 'bg-white dark:bg-slate-800 dark:text-white'
              }`}
            >
              <span className="truncate">
                {selectedRefNumbers.length > 0 ? `${selectedRefNumbers.length} فاتورة محددة` : 'كل الفواتير (حسب التاريخ)'}
              </span>
              <ChevronDown className="w-4 h-4 opacity-50" />
            </button>

            {isRefDropdownOpen && (
              <div className="absolute top-full right-0 w-full mt-2 bg-white dark:bg-slate-800 rounded-xl shadow-xl border border-slate-200 dark:border-slate-700 z-50 max-h-60 overflow-y-auto">
                 {uniqueReferences.length > 0 ? (
                   <div className="p-2 space-y-1">
                      {uniqueReferences.map((item) => {
                        const isSelected = selectedRefNumbers.includes(item.ref);
                        return (
                          <div 
                            key={item.ref} 
                            onClick={() => toggleRefSelection(item.ref)}
                            className={`flex items-start gap-3 p-2 rounded-lg cursor-pointer transition-colors ${
                              isSelected ? 'bg-emerald-50 dark:bg-emerald-900/20' : 'hover:bg-slate-50 dark:hover:bg-slate-700'
                            }`}
                          >
                            <div className={`mt-1 ${isSelected ? 'text-emerald-500' : 'text-slate-300'}`}>
                              {isSelected ? <CheckSquare className="w-4 h-4" /> : <Square className="w-4 h-4" />}
                            </div>
                            <div className="flex flex-col">
                              <span className={`text-sm font-bold font-mono ${isSelected ? 'text-emerald-700 dark:text-emerald-400' : 'text-slate-700 dark:text-slate-300'}`}>
                                {item.ref}
                              </span>
                              <span className="text-[10px] text-slate-400 font-medium">
                                {item.date}
                              </span>
                            </div>
                          </div>
                        )
                      })}
                   </div>
                 ) : (
                   <div className="p-4 text-center text-xs text-slate-400">لا توجد فواتير مسجلة</div>
                 )}
              </div>
            )}
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-bold text-slate-500 mr-1 flex items-center gap-1"><Calendar className="w-3 h-3"/> من تاريخ</label>
            <input 
              type="date" 
              disabled={selectedRefNumbers.length > 0}
              className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-xl px-3 py-2 text-sm disabled:opacity-50 disabled:bg-slate-100 disabled:cursor-not-allowed" 
              value={startDate} onChange={(e) => setStartDate(e.target.value)} 
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-bold text-slate-500 mr-1 flex items-center gap-1"><Calendar className="w-3 h-3"/> إلى تاريخ</label>
            <input 
              type="date" 
              disabled={selectedRefNumbers.length > 0}
              className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-xl px-3 py-2 text-sm disabled:opacity-50 disabled:bg-slate-100 disabled:cursor-not-allowed" 
              value={endDate} onChange={(e) => setEndDate(e.target.value)} 
            />
          </div>

          <div className="space-y-1.5">
            <label className="text-xs font-bold text-slate-500 mr-1 flex items-center gap-1"><Package className="w-3 h-3"/> الخامة</label>
            <select className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-xl px-3 py-2 text-sm" value={selectedMaterialId} onChange={(e) => setSelectedMaterialId(e.target.value)}>
              <option value="">كل الخامات</option>{materials.map(m => <option key={m.id} value={m.id}>{m.name}</option>)}
            </select>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-4 gap-4 mt-4">
           <div className="space-y-1.5">
            <label className="text-xs font-bold text-slate-500 mr-1 flex items-center gap-1"><Utensils className="w-3 h-3"/> الصنف</label>
            <select className="w-full border dark:border-slate-700 bg-white dark:bg-slate-800 dark:text-white rounded-xl px-3 py-2 text-sm" value={selectedItemId} onChange={(e) => setSelectedItemId(e.target.value)}>
              <option value="">كل الأصناف</option>{items.map(i => <option key={i.id} value={i.id}>{i.name}</option>)}
            </select>
          </div>
           <div className="lg:col-span-3 flex justify-end items-end h-full">
              <button onClick={resetFilter} className="flex items-center gap-2 px-4 py-2 text-slate-400 hover:text-rose-500 transition-all font-bold text-sm bg-slate-50 dark:bg-slate-800 rounded-lg hover:bg-rose-50 border border-transparent hover:border-rose-100"><RotateCcw className="w-4 h-4" />إعادة التصفية</button>
           </div>
        </div>

        {selectedRefNumbers.length > 0 && (
           <div className="mt-4 pt-4 border-t border-slate-100 dark:border-slate-800 flex flex-wrap gap-2 animate-in fade-in slide-in-from-top-1">
              <span className="text-xs font-bold text-slate-400 py-1">الفواتير المحددة:</span>
              {selectedRefNumbers.map(ref => (
                <span key={ref} className="bg-emerald-100 dark:bg-emerald-900/30 text-emerald-800 dark:text-emerald-300 text-xs px-2 py-1 rounded-md font-mono flex items-center gap-1">
                   {ref}
                   <button onClick={() => toggleRefSelection(ref)} className="hover:text-emerald-600"><X className="w-3 h-3" /></button>
                </span>
              ))}
              <button onClick={() => setSelectedRefNumbers([])} className="text-[10px] text-rose-500 hover:underline px-2">مسح الكل</button>
           </div>
        )}
      </div>

      <div className="flex flex-col md:flex-row items-center justify-between gap-4 no-print">
        <div className="flex bg-white dark:bg-slate-800 p-1 rounded-2xl border border-slate-200 dark:border-slate-700 shadow-sm w-fit transition-colors">
          <button onClick={() => setReportType('aggregated')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${reportType === 'aggregated' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}><Layers className="w-4 h-4" />تجميعي (تكاليف)</button>
          <button onClick={() => setReportType('detailed')} className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold transition-all ${reportType === 'detailed' ? 'bg-emerald-500 text-white shadow-lg' : 'text-slate-500'}`}><List className="w-4 h-4" />تفصيلي (ربحية)</button>
        </div>
        <div className="flex gap-3">
          <button onClick={exportCSV} className="flex items-center gap-2 text-sm text-emerald-700 bg-emerald-50 dark:bg-emerald-900/20 px-4 py-2 rounded-xl font-bold"><FileSpreadsheet className="w-4 h-4" />تصدير CSV</button>
          <button onClick={() => window.print()} className="flex items-center gap-2 text-sm text-slate-700 bg-white dark:bg-slate-800 border dark:border-slate-700 px-4 py-2 rounded-xl font-bold"><Printer className="w-4 h-4" />طباعة PDF</button>
        </div>
      </div>

      {reportType === 'aggregated' ? (
        <div className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors">
          <table className="w-full text-right">
            <thead className="bg-slate-50/50 dark:bg-slate-800/50 border-b dark:border-slate-800 text-slate-500 text-xs font-bold">
              <tr>
                <th className="px-6 py-4">المادة الخام النهائية</th>
                <th className="px-6 py-4 text-center">الكمية المستهلكة</th>
                <th className="px-6 py-4 text-center">متوسط التكلفة</th>
                <th className="px-6 py-4 text-left">التكلفة الإجمالية</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 dark:divide-slate-800">
              {aggregatedData.map((data, i) => (
                <tr key={i} className="hover:bg-slate-50 dark:hover:bg-slate-800/30 transition-colors">
                  <td className="px-6 py-4 font-bold text-slate-700 dark:text-slate-200">{data.name}</td>
                  <td className="px-6 py-4 text-center">
                    <span className="font-mono font-bold">{data.total.toLocaleString(undefined, { minimumFractionDigits: 3 })}</span> <span className="text-xs text-slate-400">{data.unit}</span>
                  </td>
                  <td className="px-6 py-4 text-center text-slate-400 font-mono text-xs">
                     {(data.totalCost / data.total).toFixed(2)}
                  </td>
                  <td className="px-6 py-4 font-mono font-bold text-emerald-600 dark:text-emerald-400 text-left">
                    {data.totalCost.toLocaleString(undefined, { minimumFractionDigits: 2 })}
                  </td>
                </tr>
              ))}
              {aggregatedData.length > 0 && (
                <tr className="bg-emerald-50/50 dark:bg-emerald-900/10 font-bold border-t-2 border-emerald-100 dark:border-emerald-800">
                  <td colSpan={3} className="px-6 py-4 text-slate-800 dark:text-slate-200">الإجمالي الكلي لتكلفة الخامات المستهلكة</td>
                  <td className="px-6 py-4 text-left font-mono text-lg text-emerald-700 dark:text-emerald-400">
                    {grandTotalAggregatedCost.toLocaleString(undefined, { minimumFractionDigits: 2 })} <span className="text-sm">ر.س</span>
                  </td>
                </tr>
              )}
              {aggregatedData.length === 0 && (
                 <tr><td colSpan={4} className="px-6 py-8 text-center text-slate-400">لا توجد بيانات للعرض حسب الفلترة المحددة</td></tr>
              )}
            </tbody>
          </table>
        </div>
      ) : (
        <div className="space-y-6">
          {detailedData.map((item, idx) => {
            const itemId = items.find(i => i.name === item.itemName)?.id;
            const directRecipe = itemId ? getDirectRecipe(itemId) : [];
            const hasSubItems = directRecipe.some(r => r.isSub);
            const profit = item.totalRevenue - item.totalCost;
            const isProfitable = profit >= 0;

            return (
              <div key={idx} className="bg-white dark:bg-slate-900 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-800 overflow-hidden transition-colors break-inside-avoid">
                <div className="p-4 bg-slate-900 dark:bg-slate-800 text-white flex flex-wrap justify-between items-center gap-3">
                  <div className="flex items-center gap-3">
                    <span className="text-lg font-bold">{item.itemName}</span>
                    {hasSubItems && (
                       <div className="bg-blue-500/20 text-blue-300 text-[10px] px-2 py-0.5 rounded-full border border-blue-500/30 flex items-center gap-1">
                         <ChefHat className="w-3 h-3" /> يتضمن مكونات مجهزة
                       </div>
                    )}
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="bg-slate-700 text-white px-3 py-1 rounded-lg text-sm font-bold">المباع: {item.quantitySold}</span>
                    <span className="bg-blue-600 text-white px-3 py-1 rounded-lg text-sm font-bold">الإيراد: {item.totalRevenue.toLocaleString()} ر.س</span>
                    <span className={`${isProfitable ? 'bg-emerald-500' : 'bg-rose-500'} text-white px-3 py-1 rounded-lg text-sm font-bold`}>الربح: {profit.toLocaleString()} ر.س</span>

                    <div className="relative group cursor-help no-print">
                      <HelpCircle className="w-5 h-5 text-slate-400" />
                      <div className="invisible group-hover:visible absolute z-50 top-full left-0 mt-2 w-64 bg-white dark:bg-slate-800 text-slate-800 dark:text-slate-200 p-4 rounded-2xl shadow-2xl border border-slate-200 dark:border-slate-700 animate-in fade-in slide-in-from-top-1 text-xs">
                        <p className="font-bold border-b border-slate-100 dark:border-slate-700 pb-2 mb-2 text-emerald-600">المكونات المباشرة للصنف:</p>
                        <ul className="space-y-1.5">
                           {directRecipe.map((r, ri) => (
                             <li key={ri} className="flex justify-between items-center">
                               <span className="flex items-center gap-2">
                                 {r.isSub ? <ChefHat className="w-3 h-3 text-blue-500" /> : <Package className="w-3 h-3 text-slate-400" />}
                                 {r.name}
                               </span>
                               <span className="font-mono text-slate-500">{r.qty}</span>
                             </li>
                           ))}
                        </ul>
                      </div>
                    </div>
                  </div>
                </div>
                <div className="p-4">
                  <h5 className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3 flex items-center gap-2">
                    <Coins className="w-3 h-3" /> تفصيل تكلفة الخامات
                  </h5>
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-3">
                    {item.ingredients.map((ing, iIdx) => (
                      <div key={iIdx} className="p-3 bg-slate-50 dark:bg-slate-800/50 rounded-xl border border-slate-100 dark:border-slate-800 flex justify-between items-center group">
                        <div className="flex items-center gap-2">
                          <div className="w-1.5 h-1.5 rounded-full bg-emerald-400"></div>
                          <span className="text-sm font-medium text-slate-600 dark:text-slate-300">{ing.materialName}</span>
                        </div>
                        <div className="text-left flex flex-col items-end">
                          <span className="font-mono font-bold text-slate-900 dark:text-white text-sm">{ing.cost.toLocaleString(undefined, { minimumFractionDigits: 2 })} ر.س</span>
                          <span className="text-[9px] text-slate-400">{ing.consumedQuantity.toFixed(2)} {ing.unit}</span>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              </div>
            );
          })}
          {detailedData.length === 0 && (
             <div className="px-6 py-12 text-center text-slate-400 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-3xl">لا توجد بيانات للعرض حسب الفلترة المحددة</div>
          )}
        </div>
      )}
    </div>
  );
};

